/**
 * 番茄小说创作助手 - Electron 主进程入口
 * 
 * 提供：
 * - 窗口管理
 * - IPC 处理器注册
 * - 文件系统 API
 * - SQLite 连接（待实现）
 */

import { app, BrowserWindow, ipcMain, dialog, shell, safeStorage } from 'electron'
import path from 'path'
import fs, { FSWatcher } from 'fs'
import { setupYamlHandlers } from './yamlService'

// 重新导出 main.ts 的功能
// 这是为了保持统一的导入路径：import { createWindow } from '../src/main/index'

// 保持对窗口对象的全局引用，避免被垃圾回收
let mainWindow: BrowserWindow | null = null

// 项目根目录 - 用于路径验证
let projectRootPath: string | null = null

// 文件系统监视器
let fsWatcher: FSWatcher | null = null

/**
 * 验证文件路径是否安全
 * 防止路径遍历攻击 (如 ../../../etc/passwd)
 * 只允许访问项目目录内的文件
 */
function validatePath(requestedPath: string): { valid: boolean; resolvedPath?: string; error?: string } {
  // 如果没有设置项目根路径，允许绝对路径但进行基本验证
  if (!projectRootPath) {
    // 解析并规范化路径
    const resolved = path.resolve(requestedPath)

    // 检查是否尝试访问系统敏感目录
    const sensitivePaths = [
      '/etc',
      '/proc',
      '/sys',
      'C:\\Windows',
      'C:\\Program Files',
      'C:\\Program Files (x86)',
    ]

    for (const sensitive of sensitivePaths) {
      if (resolved.toLowerCase().startsWith(sensitive.toLowerCase())) {
        return {
          valid: false,
          error: `访问被拒绝：不允许访问系统目录`,
        }
      }
    }

    return { valid: true, resolvedPath: resolved }
  }

  // 解析并规范化请求的路径
  const resolved = path.resolve(requestedPath)
  let normalizedRequested = path.normalize(resolved)
  let normalizedRoot = path.normalize(projectRootPath)

  // 规范化路径分隔符，确保跨平台兼容（Windows 上 / 和 \ 需要统一）
  // 将所有路径转换为统一的分隔符进行比较
  const normalizeSeparators = (p: string) => p.replace(/[\\/]/g, path.sep)
  normalizedRequested = normalizeSeparators(normalizedRequested)
  normalizedRoot = normalizeSeparators(normalizedRoot)

  // 确保请求的路径在项目根目录内
  if (!normalizedRequested.startsWith(normalizedRoot + path.sep) && normalizedRequested !== normalizedRoot) {
    return {
      valid: false,
      error: `访问被拒绝：路径必须在项目目录内 (${projectRootPath})`,
    }
  }

  return { valid: true, resolvedPath: resolved }
}

/**
 * 创建应用窗口
 */
function createWindow(): BrowserWindow {
  mainWindow = new BrowserWindow({
    width: 1400,
    height: 900,
    minWidth: 1000,
    minHeight: 700,
    title: '🍅 番茄小说创作助手',
    webPreferences: {
      preload: path.join(__dirname, '..', 'preload', 'index.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: false,
    },
    show: false,
  })

  // 窗口准备好后显示
  mainWindow.once('ready-to-show', () => {
    mainWindow?.show()
  })

  // 窗口关闭时清理
  mainWindow.on('closed', () => {
    mainWindow = null
  })

  return mainWindow
}

/**
 * 关闭应用窗口
 */
function closeWindow(): void {
  if (mainWindow) {
    mainWindow.close()
    mainWindow = null
  }
}

/**
 * 设置项目根路径
 */
function setProjectRoot(rootPath: string): void {
  projectRootPath = path.resolve(rootPath)
}

/**
 * 设置 IPC 处理器
 * 所有主进程功能通过 IPC 暴露给渲染进程
 */
function setupIpcHandlers(): void {
  // ========== 对话框 ==========
  ipcMain.handle('dialog:openDirectory', async () => {
    const result = await dialog.showOpenDialog({
      properties: ['openDirectory'],
    })

    if (!result.canceled && result.filePaths.length > 0) {
      const selectedPath = result.filePaths[0]
      setProjectRoot(selectedPath)
      return { success: true, data: selectedPath }
    }
    return { success: false, error: '未选择目录' }
  })

  // ========== 文件系统 - 读取操作 ==========
  ipcMain.handle('fs:readFile', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      const content = await fs.promises.readFile(validation.resolvedPath!, 'utf-8')
      return { success: true, content }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:exists', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, exists: false, error: validation.error }
      }

      await fs.promises.access(validation.resolvedPath!)
      return { success: true, exists: true }
    } catch (error: any) {
      if (error.code === 'ENOENT') return { success: true, exists: false }
      return { success: false, exists: false, error: error.message }
    }
  })

  ipcMain.handle('fs:readdir', async (_event, dirPath: string) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      const entries = await fs.promises.readdir(validation.resolvedPath!, { withFileTypes: true })
      const result = entries.map(entry => ({
        name: entry.name,
        isDirectory: entry.isDirectory(),
        isFile: entry.isFile(),
      }))
      return { success: true, data: result }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 文件系统 - 写入操作 ==========
  ipcMain.handle('fs:writeFile', async (_event, filePath: string, content: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      // 确保父目录存在
      const dir = path.dirname(validation.resolvedPath!)
      await fs.promises.mkdir(dir, { recursive: true })

      await fs.promises.writeFile(validation.resolvedPath!, content, 'utf-8')
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:mkdir', async (_event, dirPath: string) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.mkdir(validation.resolvedPath!, { recursive: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 文件系统 - 删除操作 ==========
  ipcMain.handle('fs:unlink', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.unlink(validation.resolvedPath!)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:rmdir', async (_event, dirPath: string, options?: { recursive?: boolean }) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.rm(validation.resolvedPath!, { recursive: options?.recursive, force: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:remove', async (_event, targetPath: string) => {
    try {
      const validation = validatePath(targetPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.rm(validation.resolvedPath!, { recursive: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:rename', async (_event, oldPath: string, newPath: string) => {
    try {
      const oldValidation = validatePath(oldPath)
      const newValidation = validatePath(newPath)

      if (!oldValidation.valid) {
        return { success: false, error: oldValidation.error }
      }
      if (!newValidation.valid) {
        return { success: false, error: newValidation.error }
      }

      await fs.promises.rename(oldValidation.resolvedPath!, newValidation.resolvedPath!)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 系统 ==========
  ipcMain.handle('shell:openPath', async (_event, path: string) => {
    const validation = validatePath(path)
    if (!validation.valid) {
      return { success: false, error: validation.error }
    }
    const result = await shell.openPath(validation.resolvedPath!)
    if (result === '') {
      return { success: true }
    }
    return { success: false, error: result }
  })

  // ========== 项目 ==========
  ipcMain.handle('project:getRoot', () => {
    return projectRootPath
  })

  ipcMain.handle('project:setRoot', (_event, rootPath: string) => {
    setProjectRoot(rootPath)
    return projectRootPath
  })

  // ========== 文件系统监听 ==========
  ipcMain.handle('fs:watch', async (_event, dirPath?: string) => {
    try {
      // 停止之前的监视
      if (fsWatcher) {
        await fsWatcher.close()
        fsWatcher = null
      }

      const validation = dirPath ? validatePath(dirPath) : null
      if (dirPath && validation && !validation.valid) {
        return { success: false, error: validation.error }
      }
      const watchPath = validation?.resolvedPath ?? projectRootPath

      if (!watchPath) {
        return { success: false, error: '没有可监视的路径' }
      }

      fsWatcher = fs.watch(watchPath, { recursive: true }, (eventType, filename) => {
        if (filename && mainWindow) {
          mainWindow.webContents.send('fs:change', {
            type: eventType,
            fileName: filename,
            path: path.join(watchPath, filename),
          })
        }
      })

      return { success: true, path: watchPath }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:unwatch', async () => {
    try {
      if (fsWatcher) {
        await fsWatcher.close()
        fsWatcher = null
      }
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 安全存储 ==========
  ipcMain.handle('safeStorage:encrypt', async (_event, plainText: string) => {
    try {
      if (!safeStorage.isEncryptionAvailable()) {
        return { success: false, error: '加密不可用' }
      }
      const encrypted = safeStorage.encryptString(plainText)
      return { success: true, data: encrypted }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('safeStorage:decrypt', async (_event, encrypted: number[] | Uint8Array) => {
    try {
      if (!safeStorage.isEncryptionAvailable()) {
        return { success: false, error: '加密不可用' }
      }
      const decrypted = safeStorage.decryptString(Buffer.from(encrypted))
      return { success: true, data: decrypted }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('safeStorage:isAvailable', () => {
    return { success: true, available: safeStorage.isEncryptionAvailable() }
  })

  // ========== AI 服务 ==========
  // 导入 AI 服务
  const { setupAiHandlers } = require('./aiService')
  setupAiHandlers(ipcMain)

  // ========== 备份服务 ==========
  // 导入备份服务
  const { setupBackupHandlers } = require('./backupService')
  setupBackupHandlers(ipcMain)

  // ========== YAML 服务 ==========
  setupYamlHandlers(ipcMain, () => projectRootPath)
}

/**
 * 启动应用
 */
async function startApp(): Promise<void> {
  // 设置 IPC 处理器
  setupIpcHandlers()

  // 创建窗口
  createWindow()

  // 加载应用
  if (process.env.NODE_ENV === 'development') {
    await mainWindow?.loadURL('http://localhost:5173')
    mainWindow?.webContents.openDevTools()
  } else {
    await mainWindow?.loadFile(path.join(__dirname, '../renderer/index.html'))
  }
}

// 应用就绪
app.whenReady().then(startApp)

// 所有窗口关闭时退出
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow()
  }
})

// 导出供测试和主进程入口使用
export { 
  createWindow, 
  closeWindow, 
  setupIpcHandlers, 
  setProjectRoot,
  startApp,
  projectRootPath 
}

/**
 * 备份服务 - 主进程 IPC 处理器
 * 处理小说项目的备份/恢复
 */

import { IpcMain, app } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import zlib from 'node:zlib'
import { promisify } from 'node:util'

const gzip = promisify(zlib.gzip)
const gunzip = promisify(zlib.gunzip)

const BACKUP_DIR = path.join(app.getPath('userData'), 'backups')
const BACKUP_INDEX = path.join(BACKUP_DIR, 'index.json')

interface BackupEntry {
  name: string
  path: string
  date: string
  size: number
  description?: string
}

function loadIndex(): BackupEntry[] {
  if (!fs.existsSync(BACKUP_INDEX)) return []
  try {
    return JSON.parse(fs.readFileSync(BACKUP_INDEX, 'utf-8'))
  } catch {
    return []
  }
}

function saveIndex(index: BackupEntry[]): void {
  fs.mkdirSync(BACKUP_DIR, { recursive: true })
  const tmp = BACKUP_INDEX + '.tmp'
  fs.writeFileSync(tmp, JSON.stringify(index, null, 2), 'utf-8')
  fs.renameSync(tmp, BACKUP_INDEX)  // atomic replace
}

// 递归压缩目录为一个 gzip 文件
async function compressDir(dirPath: string, relativeRoot: string): Promise<Buffer> {
  const entries: { path: string; relativePath: string; isDir: boolean }[] = []

  function walk(dir: string): void {
    let items: string[]
    try {
      items = fs.readdirSync(dir)
    } catch {
      // 权限拒绝或损坏的目录项，跳过
      return
    }
    for (const item of items) {
      const full = path.join(dir, item)
      const rel = path.relative(relativeRoot, full)
      let stat
      try {
        stat = fs.statSync(full)
      } catch {
        // symlink loop、权限拒绝等，跳过此项
        continue
      }
      if (stat.isDirectory()) {
        entries.push({ path: full, relativePath: rel + '/', isDir: true })
        try { walk(full) } catch { /* 子目录访问被拒，继续其他分支 */ }
      } else {
        entries.push({ path: full, relativePath: rel, isDir: false })
      }
    }
  }
  walk(dirPath)

  // 构建文件列表 JSON
  const manifest = JSON.stringify(entries, null, 2)
  const manifestBuf = Buffer.from(manifest, 'utf-8')

  const parts: Buffer[] = []
  // 格式：4字节manifest长度 + manifest JSON + 各文件内容
  const manifestLenBuf = Buffer.alloc(4)
  manifestLenBuf.writeUInt32BE(manifestBuf.length, 0)
  parts.push(manifestLenBuf, manifestBuf)

  for (const entry of entries) {
    if (entry.isDir) continue
    const content = fs.readFileSync(entry.path)
    const nameBuf = Buffer.from(entry.relativePath, 'utf-8')
    const nameLenBuf = Buffer.alloc(2)
    nameLenBuf.writeUInt16BE(nameBuf.length, 0)
    const sizeBuf = Buffer.alloc(4)
    sizeBuf.writeUInt32BE(content.length, 0)
    parts.push(nameLenBuf, nameBuf, sizeBuf, content)
  }

  const combined = Buffer.concat(parts)
  return gzip(combined)
}

async function decompressBackup(
  archivePath: string,
  targetDir: string
): Promise<void> {
  const raw = fs.readFileSync(archivePath)
  const decompressed = await gunzip(raw)

  let offset = 0

  // 读取 manifest
  const manifestLen = decompressed.readUInt32BE(offset)
  offset += 4
  const manifest = JSON.parse(decompressed.slice(offset, offset + manifestLen).toString('utf-8'))
  offset += manifestLen

  // P0-2 修复：原子性 — 先将原内容移到临时备份，成功后再清理
  const tmpDir = targetDir + '.restoring'
  if (fs.existsSync(targetDir)) {
    fs.renameSync(targetDir, tmpDir)
  }

  try {
    fs.mkdirSync(targetDir, { recursive: true })

    // 恢复每个文件
    for (const entry of manifest) {
      if (entry.isDir) {
        fs.mkdirSync(path.join(targetDir, entry.relativePath), { recursive: true })
        continue
      }

      const nameLen = decompressed.readUInt16BE(offset)
      offset += 2
      // skip name (already have from manifest)
      offset += nameLen
      const size = decompressed.readUInt32BE(offset)
      offset += 4
      const content = decompressed.slice(offset, offset + size)
      offset += size

      const fullPath = path.join(targetDir, entry.relativePath)
      // 禁止符号链接（防止链接到外部路径）
      try {
        const st = fs.lstatSync(fullPath)
        if (st.isSymbolicLink()) throw new Error(`禁止写入符号链接: ${entry.relativePath}`)
      } catch (e: any) {
        if (e.message.includes('禁止写入')) throw e
        // 文件不存在或无权访问，跳过
        offset += 0
        continue
      }
      // 路径越界校验
      const resolved = path.resolve(fullPath)
      if (!resolved.startsWith(path.resolve(targetDir) + path.sep)) {
        throw new Error(`路径越界: ${entry.relativePath}`)
      }
      fs.mkdirSync(path.dirname(fullPath), { recursive: true })
      fs.writeFileSync(fullPath, content)
    }

    // 全部成功，清理旧备份
    if (fs.existsSync(tmpDir)) {
      fs.rmSync(tmpDir, { recursive: true })
    }
  } catch (err) {
    // 失败则回滚：恢复原目录，清理临时目录
    if (fs.existsSync(tmpDir)) {
      if (fs.existsSync(targetDir)) {
        fs.rmSync(targetDir, { recursive: true })
      }
      fs.renameSync(tmpDir, targetDir)
    }
    throw err
  }
}

function getBackupSize(archivePath: string): number {
  try {
    return fs.statSync(archivePath).size
  } catch (err: any) {
    if (err.code === 'ENOENT') return 0
    // 权限拒绝等错误返回 -1 以区分"不存在"和"无权访问"
    console.warn(`[backupService] getBackupSize failed for ${archivePath}: ${err.message}`)
    return -1
  }
}

export function setupBackupHandlers(ipcMain: IpcMain): void {
  // 创建备份
  ipcMain.handle('backup:create', async (_event, projectPath?: string) => {
    try {
      if (!projectPath) {
        return { success: false, error: '未提供项目路径' }
      }
      // 确保备份目录存在（parent of BACKUP_DIR may not exist）
      if (!fs.existsSync(BACKUP_DIR)) {
        fs.mkdirSync(BACKUP_DIR, { recursive: true })
      }
      if (!fs.existsSync(projectPath)) {
        return { success: false, error: '项目路径不存在' }
      }

      const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19)
      const name = path.basename(projectPath) + '_' + timestamp
      const archivePath = path.join(BACKUP_DIR, name + '.nbackup')

      const archive = await compressDir(projectPath, projectPath)
      fs.writeFileSync(archivePath, archive)

      const entry: BackupEntry = {
        name,
        path: archivePath,
        date: new Date().toISOString(),
        size: archive.length,
      }

      const index = loadIndex()
      index.unshift(entry)
      saveIndex(index)

      return { success: true, backupPath: archivePath }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 列出备份
  ipcMain.handle('backup:list', async () => {
    try {
      const index = loadIndex()
      // 清理不存在的备份记录
      const valid = index.filter(e => fs.existsSync(e.path))
      if (valid.length !== index.length) {
        saveIndex(valid)
      }
      return {
        success: true,
        backups: valid.map(e => ({
          name: e.name,
          path: e.path,
          date: e.date,
          size: e.size,
        })),
      }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 恢复备份
  ipcMain.handle('backup:restore', async (_event, backupPath: string, targetPath?: string) => {
    try {
      if (!fs.existsSync(backupPath)) {
        return { success: false, error: '备份文件不存在' }
      }
      if (!targetPath) {
        return { success: false, error: '未提供恢复目标路径' }
      }
      // 验证目标路径安全（防止路径遍历）
      const resolved = path.resolve(targetPath)
      if (resolved.startsWith('/etc') || resolved.match(/^[A-Z]:\\(Windows|Program Files)/i)) {
        return { success: false, error: '禁止恢复到系统路径' }
      }

      await decompressBackup(backupPath, targetPath)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 删除备份
  ipcMain.handle('backup:delete', async (_event, backupPath: string) => {
    try {
      if (fs.existsSync(backupPath)) {
        fs.unlinkSync(backupPath)
      }
      const index = loadIndex()
      saveIndex(index.filter(e => e.path !== backupPath))
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })
}

/**
 * YAML 服务 - 主进程 IPC 处理器
 * 提供 YAML 文件的安全读写，解析和序列化
 * 所有路径操作必须经过 validatePath 验证，防止目录遍历攻击
 */

import { IpcMain } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import yaml from 'js-yaml'

// ─── 路径验证（与 index.ts 保持一致） ───────────────────────────────────────

function validateYamlPath(requestedPath: string, projectRoot: string | null): { valid: boolean; resolvedPath?: string; error?: string } {
  const normalized = path.normalize(path.resolve(requestedPath))
  const normalizeSeparators = (p: string) => p.replace(/[\\/]/g, '/')
  const normalizedWithConsistentSeparators = normalizeSeparators(normalized)

  // 项目根目录约束
  if (projectRoot) {
    const normalizedRoot = normalizeSeparators(path.normalize(path.resolve(projectRoot)))
    if (!normalizedWithConsistentSeparators.startsWith(normalizedRoot + '/')) {
      return { valid: false, error: `访问被拒绝：路径必须在项目目录内 (${projectRoot})` }
    }
  }

  const sensitivePaths = [
    'C:\\Windows',
    'C:\\Program Files',
    '/etc',
    '/usr',
    '/root',
    '/home',
  ]

  for (const sensitive of sensitivePaths) {
    if (normalizedWithConsistentSeparators.toLowerCase().startsWith(normalizeSeparators(sensitive).toLowerCase())) {
      return { valid: false, error: `禁止访问系统路径: ${sensitive}` }
    }
  }

  return { valid: true, resolvedPath: normalized }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupYamlHandlers(ipcMain: IpcMain, getProjectRoot: () => string | null): void {
  ipcMain.handle('yaml:read', async (_event, filePath: string): Promise<{ success: boolean; data?: any; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath, getProjectRoot())
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      if (!fs.existsSync(validation.resolvedPath!)) {
        return { success: false, error: '文件不存在' }
      }
      const content = fs.readFileSync(validation.resolvedPath!, 'utf-8')
      const data = yaml.load(content, { schema: yaml.FAILSAFE_SCHEMA })
      return { success: true, data }
    } catch (e: any) {
      return { success: false, error: `YAML 解析失败: ${e.message}` }
    }
  })

  ipcMain.handle('yaml:write', async (_event, filePath: string, data: any): Promise<{ success: boolean; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath, getProjectRoot())
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      const dir = path.dirname(validation.resolvedPath!)
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true })
      }
      const yamlStr = yaml.dump(data, {
        indent: 2,
        skipInvalid: true,
        noRefs: true,
        schema: yaml.FAILSAFE_SCHEMA,
      })
      fs.writeFileSync(validation.resolvedPath!, yamlStr, 'utf-8')
      return { success: true }
    } catch (e: any) {
      return { success: false, error: `YAML 写入失败: ${e.message}` }
    }
  })
}

/**
 * AI 服务 - 主进程 IPC 处理器
 * 处理渲染进程发来的 AI 相关 IPC 调用
