import { IpcMain, BrowserWindow } from 'electron'
import axios, { AxiosError } from 'axios'
import fs from 'node:fs'
import path from 'node:path'
import os from 'node:os'
import { app } from 'electron'

// ─── 配置路径 ────────────────────────────────────────────────────────────────

function getSettingsPath(): string {
  return path.join(app.getPath('userData'), 'ai-settings.json')
}

// ─── 配置读写 ────────────────────────────────────────────────────────────────

interface AiSettings {
  deepseekApiKey?: string
  doubaoApiKey?: string
  [key: string]: string | undefined
}

function loadSettings(): AiSettings {
  const p = getSettingsPath()
  if (fs.existsSync(p)) {
    try {
      return JSON.parse(fs.readFileSync(p, 'utf-8'))
    } catch {
      return {}
    }
  }
  return {}
}

function saveSettings(settings: AiSettings): void {
  const p = getSettingsPath()
  fs.mkdirSync(path.dirname(p), { recursive: true })
  fs.writeFileSync(p, JSON.stringify(settings, null, 2), 'utf-8')
}

// ─── API 调用 ────────────────────────────────────────────────────────────────

interface CallOptions {
  model?: string
  systemPrompt?: string
  temperature?: number
  maxTokens?: number
  topP?: number
  presencePenalty?: number
  frequencyPenalty?: number
}

async function callAI(
  prompt: string,
  options: CallOptions = {}
): Promise<{ success: boolean; content?: string; reasoning?: string; error?: string }> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const fallbackKey = model.startsWith('doubao')
    ? process.env.DOUBAO_API_KEY
    : process.env.DEEPSEEK_API_KEY
  const apiKey = loadSettings()[`${model}ApiKey`] || fallbackKey

  if (!apiKey) {
    return {
      success: false,
      error: `未配置 API Key。请先在设置中配置 ${model} 的 API Key。`,
    }
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    if (isDeepSeek) {
      const deepseekModel = model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat'
      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        {
          model: deepseekModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    if (model === 'doubao-pro' || model === 'doubao-lite' || model === 'doubao-mini') {
      const endpoint = 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'

      const doubaoModel = model === 'doubao-pro'
        ? 'doubao-pro-32k'
        : model === 'doubao-lite'
          ? 'doubao-lite-32k'
          : 'doubao-mini'

      const response = await axios.post(
        endpoint,
        {
          model: doubaoModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    return { success: false, error: `不支持的模型: ${model}` }
  } catch (err) {
    const axiosErr = err as AxiosError
    if (axiosErr.response) {
      return { success: false, error: `API 错误 ${axiosErr.response.status}: ${JSON.stringify(axiosErr.response.data)}` }
    }
    return { success: false, error: `请求失败: ${axiosErr.message}` }
  }
}

async function streamAI(
  prompt: string,
  options: CallOptions,
  sendChunk: (content: string, done: boolean, reasoning?: string) => void,
  sendError: (error: string) => void
): Promise<void> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const fallbackKey = model.startsWith('doubao')
    ? process.env.DOUBAO_API_KEY
    : process.env.DEEPSEEK_API_KEY
  const apiKey = loadSettings()[`${model}ApiKey`] || fallbackKey

  if (!apiKey) {
    sendError(`未配置 API Key。请先在设置中配置 ${model} 的 API Key。`)
    sendChunk('', true)
    return
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    }

    const resolvedModel = isDeepSeek
      ? (model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat')
      : (model === 'doubao-pro' ? 'doubao-pro-32k'
        : model === 'doubao-lite' ? 'doubao-lite-32k'
        : model === 'doubao-mini' ? 'doubao-mini'
        : 'doubao-pro-32k')

    const body: Record<string, unknown> = {
      model: resolvedModel,
      messages: [
        ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
        { role: 'user', content: prompt },
      ],
      temperature,
      max_tokens: maxTokens,
    }

    // DeepSeek（实际也是火山引擎 Doubao 端）支持流式
    if (isDeepSeek) {
      body.stream = true

      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        body,
        {
          headers,
          responseType: 'stream',
          timeout: 120000,
        }
      )

      const stream = response.data as import('node:stream').Stream
      let buffer = ''

      await new Promise<void>((resolve, reject) => {
        stream.on('data', (chunk: Buffer) => {
          buffer += chunk.toString()
          const lines = buffer.split('\n')
          buffer = lines.pop() || ''

          for (const line of lines) {
            const trimmed = line.trim()
            if (!trimmed || trimmed === 'data: [DONE]') continue
            if (!trimmed.startsWith('data: ')) continue
            const data = trimmed.slice(6)
            try {
              const parsed = JSON.parse(data)
              const content = parsed.choices?.[0]?.delta?.content || ''
              const reasoning = parsed.choices?.[0]?.delta?.reasoning || ''
              if (content || reasoning) {
                sendChunk(content, false, reasoning)
              }
            } catch (e) { console.warn('流式数据解析失败:', e) }
          }
        })

        stream.on('end', () => {
          if (buffer.trim() && buffer.trim() !== '[DONE]') {
            try {
              const data = JSON.parse(buffer.slice(6))
              const content = data.choices?.[0]?.delta?.content || ''
              if (content) sendChunk(content, false)
            } catch (e) { console.warn('流式数据解析失败:', e) }
          }
          sendChunk('', true)
          resolve()
        })

        stream.on('error', (err: Error) => {
          sendError(err.message)
          sendChunk('', true)
          resolve()
        })
      })
    } else {
      // 非流式降级
      const result = await callAI(prompt, options)
      if (result.success) {
        sendChunk(result.content || '', false)
        sendChunk('', true)
      } else {
        sendError(result.error || '未知错误')
        sendChunk('', true)
      }
    }
  } catch (err) {
    const axiosErr = err as AxiosError
    sendError(axiosErr.message || '请求失败')
    sendChunk('', true)
  }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupAiHandlers(ipcMain: IpcMain): void {
  // 保存 API Key
  ipcMain.handle('ai:saveApiKey', async (_event, service: string, apiKey: string) => {
    try {
      const settings = loadSettings()
      settings[`${service}ApiKey`] = apiKey
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 检查是否已配置
  ipcMain.handle('ai:isConfigured', async (_event, service: string) => {
    const settings = loadSettings()
    const envKey = service === 'deepseek' ? 'DEEPSEEK_API_KEY' : 'DOUBAO_API_KEY'
    const configured = !!(settings[`${service}ApiKey`] || process.env[envKey])
    return { success: true, configured }
  })

  // 获取已配置的服务列表
  ipcMain.handle('ai:getConfiguredServices', async () => {
    const settings = loadSettings()
    const services: string[] = []
    if (settings.deepseekApiKey || process.env.DEEPSEEK_API_KEY) services.push('deepseek')
    if (settings.doubaoApiKey || process.env.DOUBAO_API_KEY) services.push('doubao')
    return { success: true, services }
  })

  // AI 调用（非流式）
  ipcMain.handle('ai:call', async (_event, prompt: string, options?: CallOptions) => {
    return callAI(prompt, options || {})
  })

  // AI 流式调用
  ipcMain.handle('ai:stream', async (event, prompt: string, options?: CallOptions) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (!win || win.isDestroyed()) return { success: false, error: '窗口已关闭' }

    await streamAI(
      prompt,
      options || {},
      (content, done, reasoning) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-chunk', { content, done, reasoning })
        }
      },
      (error) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-error', error)
        }
      }
    )

    return { success: true }
  })

  // 测试连接
  ipcMain.handle('ai:testConnection', async (_event, service: string) => {
    const testPrompt = '请回复"连接成功"，不需要其他内容。'
    const result = await callAI(testPrompt, { model: service, maxTokens: 50 })
    return { success: result.success, result: result.success, error: result.error }
  })

  // 保存设置
  ipcMain.handle('ai:saveSetting', async (_event, key: string, value: any) => {
    try {
      const settings = loadSettings()
      settings[key] = value
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 读取设置
  ipcMain.handle('ai:getSetting', async (_event, key: string, defaultValue?: any) => {
    const settings = loadSettings()
    return { success: true, value: settings[key] ?? defaultValue }
  })
}

/**
 * 番茄小说创作助手 - 预加载脚本入口
 * 
 * 暴露安全的 API 给渲染进程
 * 所有 API 通过 contextBridge 暴露
 */

import { contextBridge, ipcRenderer } from 'electron'

// 重新导出 preload.ts 的功能
// 保持统一的导入路径

/**
 * 暴露安全的 API 给渲染进程
 */
function exposeElectronAPI(): void {
  contextBridge.exposeInMainWorld('electronAPI', {
    // 对话框
    openDirectory: () => ipcRenderer.invoke('dialog:openDirectory'),

    // 文件系统 - 读取操作
    readFile: (filePath: string) => ipcRenderer.invoke('fs:readFile', filePath),
    exists: (filePath: string) => ipcRenderer.invoke('fs:exists', filePath),
    readdir: (dirPath: string) => ipcRenderer.invoke('fs:readdir', dirPath),

    // 文件系统 - 写入操作
    writeFile: (filePath: string, content: string) => 
      ipcRenderer.invoke('fs:writeFile', filePath, content),
    mkdir: (dirPath: string) => ipcRenderer.invoke('fs:mkdir', dirPath),

    // 文件系统 - 删除操作
    unlink: (filePath: string) => ipcRenderer.invoke('fs:unlink', filePath),
    rmdir: (dirPath: string, options?: { recursive?: boolean }) => 
      ipcRenderer.invoke('fs:rmdir', dirPath, options),
    remove: (targetPath: string) => ipcRenderer.invoke('fs:remove', targetPath),

    // 便捷删除方法
    deleteFile: (filePath: string) => ipcRenderer.invoke('fs:unlink', filePath),
    deleteDirectory: (dirPath: string) => ipcRenderer.invoke('fs:rmdir', dirPath, { recursive: true }),
    renameFile: (oldPath: string, newPath: string) => ipcRenderer.invoke('fs:rename', oldPath, newPath),

    // 系统
    openPath: (path: string) => ipcRenderer.invoke('shell:openPath', path),

    // 项目
    getProjectRoot: () => ipcRenderer.invoke('project:getRoot'),
    setProjectRoot: (rootPath: string) => ipcRenderer.invoke('project:setRoot', rootPath),

    // 文件系统监听
    fsWatch: (dirPath?: string) => ipcRenderer.invoke('fs:watch', dirPath),
    fsUnwatch: () => ipcRenderer.invoke('fs:unwatch'),
    onFsChange: (callback: (data: { type: string; fileName: string; path: string }) => void) => {
      const handler = (_event: any, data: any) => callback(data)
      ipcRenderer.on('fs:change', handler)
      return () => ipcRenderer.removeListener('fs:change', handler)
    },

    // 安全存储 - 用于加密存储 API Key 等敏感信息
    safeStorage: {
      encrypt: (plainText: string) => ipcRenderer.invoke('safeStorage:encrypt', plainText),
      decrypt: (encrypted: Uint8Array | number[]) => ipcRenderer.invoke('safeStorage:decrypt', Array.from(encrypted)),
      isAvailable: () => ipcRenderer.invoke('safeStorage:isAvailable'),
    },

    // ==================== YAML 服务 API ====================
    yaml: {
      read: (filePath: string) => ipcRenderer.invoke('yaml:read', filePath),
      write: (filePath: string, data: any) => ipcRenderer.invoke('yaml:write', filePath, data),
    },

    // ==================== AI 服务 API ====================

    // AI Key 管理
    ai: {
      saveApiKey: (service: string, apiKey: string) => 
        ipcRenderer.invoke('ai:saveApiKey', service, apiKey),

      isConfigured: (service: string) => 
        ipcRenderer.invoke('ai:isConfigured', service),

      getConfiguredServices: () => 
        ipcRenderer.invoke('ai:getConfiguredServices'),

      call: (prompt: string, options?: any) => 
        ipcRenderer.invoke('ai:call', prompt, options),

      stream: (prompt: string, options?: any) => 
        ipcRenderer.invoke('ai:stream', prompt, options),

      onStreamChunk: (callback: (chunk: { content: string; done: boolean; reasoning?: string }) => void) => {
        const handler = (_event: any, chunk: any) => callback(chunk as { content: string; done: boolean; reasoning?: string })
        ipcRenderer.on('ai:stream-chunk', handler)
        return () => ipcRenderer.removeListener('ai:stream-chunk', handler)
      },

      onStreamError: (callback: (error: string) => void) => {
        const handler = (_event: any, error: any) => callback(error as string)
        ipcRenderer.on('ai:stream-error', handler)
        return () => ipcRenderer.removeListener('ai:stream-error', handler)
      },

      testConnection: (service: string) => 
        ipcRenderer.invoke('ai:testConnection', service),

      saveSetting: (key: string, value: any) => 
        ipcRenderer.invoke('ai:saveSetting', key, value),

      getSetting: (key: string, defaultValue?: any) => 
        ipcRenderer.invoke('ai:getSetting', key, defaultValue),
    },

    // ==================== 备份服务 API ====================

    backup: {
      create: (projectPath: string) => ipcRenderer.invoke('backup:create', projectPath),
      list: () => ipcRenderer.invoke('backup:list'),
      restore: (backupPath: string, targetPath: string) => ipcRenderer.invoke('backup:restore', backupPath, targetPath),
      delete: (backupPath: string) => ipcRenderer.invoke('backup:delete', backupPath),
    },
  })
}

