const ProjectManager: React.FC<ProjectManagerProps> = ({
  visible,
  mode: initialMode,
  onClose,
  onProjectOpened,
}) => {
  const [mode, setMode] = useState<'create' | 'list'>(initialMode || 'create')
  const [form] = Form.useForm()
  const [creating, setCreating] = useState(false)
  const [recentProjects, setRecentProjects] = useState<ProjectInfo[]>([])

  // 加载最近项目
  const loadRecentProjects = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('recentProjects', [])
      if (result.success && result.value) {
        setRecentProjects(result.value as ProjectInfo[])
      }
    } catch {
      // ignore
    }
  }

  useEffect(() => {
    if (visible) {
      loadRecentProjects()
      setMode(initialMode || 'create')
    }
  }, [visible, initialMode])

  // 创建新项目
  const handleCreateProject = async () => {
    if (!window.electronAPI) {
      message.error('系统未就绪，请刷新页面或重启应用')
      return
    }
    try {
      const values = await form.validateFields()
      setCreating(true)

      // 弹出目录选择对话框
      const dirResult = await window.electronAPI.openDirectory()
      if (!dirResult.success || !dirResult.data) {
        setCreating(false)
        return
      }

      const projectName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const projectPath = path.join(dirResult.data, projectName)

      // 创建项目目录结构
      await createProjectStructure(projectPath, values)

      // 添加到最近项目
      const projectInfo: ProjectInfo = {
        name: values.name,
        path: projectPath,
        genre: values.genre,
        status: 'planning',
        lastModified: new Date().toISOString().split('T')[0],
      }

      setRecentProjects((prev: ProjectInfo[]) => {
        const updated = [projectInfo, ...prev.filter(p => p.path !== projectPath)].slice(0, 10)
        window.electronAPI.ai.saveSetting('recentProjects', updated).catch(console.error)
        return updated
      })

      message.success(`项目「${values.name}」创建成功！`)
      onProjectOpened(projectPath)
      onClose()
    } catch (error) {
      console.error('创建项目失败:', error)
      message.error('创建项目失败')
    } finally {
      setCreating(false)
    }
  }

  // 创建项目目录结构
  const createProjectStructure = async (
    projectPath: string,
    projectInfo: Record<string, unknown>
  ) => {
    // project.yaml
    const projectYaml = {
      title: projectInfo.name,
      author: projectInfo.author || '你的名字',
      genre: projectInfo.genre || 'xianxia',
      target_words: projectInfo.targetWords || 200000,
      status: 'planning',
      created: new Date().toISOString().split('T')[0],
      last_modified: new Date().toISOString().split('T')[0],
    }

    // project.yaml
    const yamlResult = await window.electronAPI.yaml.write(
      `${projectPath}/project.yaml`,
      projectYaml
    )
    if (!yamlResult.success) {
      throw new Error(`创建 project.yaml 失败: ${yamlResult.error}`)
    }

    // plots 目录和示例章节
    const plotsPath = path.join(projectPath, 'plots')
    const volumePath = path.join(plotsPath, '第一卷_觉醒')
    const mkdirResult = await window.electronAPI.mkdir(volumePath)
    if (!mkdirResult.success) {
      throw new Error(`创建目录失败: ${mkdirResult.error}`)
    }

    // 示例章节
    const sampleChapter = `# 第一章 重生

睁开眼，熟悉的场景映入眼帘。

这是……青云宗？

林枫猛地坐起身，环顾四周。一切都那么熟悉，却又带着一种说不出的陌生感。

他记得自己明明已经死了，死在血魔宗那场围杀之中。可是现在……

低头看着自己的双手，年轻而有力。这双手，应该已经在五百年前那场大战中化为灰烬了。

\"我……重生了？\"

林枫喃喃自语，眼中闪过一丝复杂的光芒。前世的记忆如潮水般涌来——血魔的背叛、师门的覆灭、以及那场改变一切的决战。

既然上天给了他第二次机会……

这一世，他绝不会再让悲剧重演。

血魔宗，你们等着！
`

    // 示例章节文件
    const writeChapterResult = await window.electronAPI.writeFile(
      path.join(volumePath, '第一章_重生.md'),
      sampleChapter
    )
    if (!writeChapterResult.success) {
      throw new Error(`创建章节文件失败: ${writeChapterResult.error}`)
    }

    const writePlanResult = await window.electronAPI.writeFile(
      path.join(volumePath, '_plan.yaml'),
      DEFAULT_PROJECT_STRUCTURE.plots['第一卷_觉醒']['_plan.yaml']
    )
    if (!writePlanResult.success) {
      throw new Error(`创建章节计划失败: ${writePlanResult.error}`)
    }

    // characters 目录
    const mkdirCharsResult = await window.electronAPI.mkdir(path.join(projectPath, 'characters'))
    if (!mkdirCharsResult.success) {
      throw new Error(`创建 characters 目录失败: ${mkdirCharsResult.error}`)
    }

    // settings 目录
    const mkdirSettingsResult = await window.electronAPI.mkdir(path.join(projectPath, 'settings'))
    if (!mkdirSettingsResult.success) {
      throw new Error(`创建 settings 目录失败: ${mkdirSettingsResult.error}`)
    }

    // facts 目录
    const mkdirFactsResult = await window.electronAPI.mkdir(path.join(projectPath, 'facts'))
    if (!mkdirFactsResult.success) {
      throw new Error(`创建 facts 目录失败: ${mkdirFactsResult.error}`)
    }

    const writeFactsResult = await window.electronAPI.yaml.write(
      path.join(projectPath, 'facts', 'plot_facts.yaml'),
      { 伏笔清单: [] }
    )
    if (!writeFactsResult.success) {
      throw new Error(`创建 plot_facts.yaml 失败: ${writeFactsResult.error}`)
    }

    // relationships.yaml
    const writeRelationshipsResult = await window.electronAPI.writeFile(
      `${projectPath}/relationships.yaml`,
      DEFAULT_PROJECT_STRUCTURE['relationships.yaml']
    )
    if (!writeRelationshipsResult.success) {
      throw new Error(`创建 relationships.yaml 失败: ${writeRelationshipsResult.error}`)
    }
  }

  // 打开最近项目
  const handleOpenRecentProject = (project: ProjectInfo) => {
    onProjectOpened(project.path)
    onClose()
  }

  // 删除最近项目记录
  const handleRemoveRecentProject = async (project: ProjectInfo) => {
    const updated = recentProjects.filter(p => p.path !== project.path)
    setRecentProjects(updated)
    await window.electronAPI.ai.saveSetting('recentProjects', updated)
    message.success('已从列表中移除')
  }

  return (
    <Modal
      title={mode === 'create' ? '📖 创建新项目' : '📂 最近项目'}
      open={visible}
      onCancel={onClose}
      width={600}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <Button
          type={mode === 'create' ? 'primary' : 'default'}
          onClick={() => setMode('create')}
        >
          创建新项目
        </Button>
        <Button
          type={mode === 'list' ? 'primary' : 'default'}
          onClick={() => setMode('list')}
        >
          最近项目
        </Button>
      </div>

      {mode === 'create' ? (
        <Form
          form={form}
          layout="vertical"
          initialValues={{
            genre: 'xianxia',
            targetWords: 200000,
            author: '',
          }}
        >
          <Form.Item
            name="name"
            label="项目名称"
            rules={[{ required: true, message: '请输入项目名称' }]}
          >
            <Input placeholder="如：剑仙归来、都市修仙传" />
          </Form.Item>

          <Form.Item name="author" label="作者">
            <Input placeholder="你的笔名（可选）" />
          </Form.Item>

          <Form.Item
            name="genre"
            label="题材类型"
            rules={[{ required: true, message: '请选择题材' }]}
          >
            <Select options={GENRE_OPTIONS} />
          </Form.Item>

          <Form.Item
            name="targetWords"
            label="目标字数"
          >
            <Select
              options={[
                { value: 50000, label: '5万字（短篇）' },
                { value: 100000, label: '10万字（中篇）' },
                { value: 200000, label: '20万字（长篇）' },
                { value: 500000, label: '50万字（超长篇）' },
                { value: 1000000, label: '100万字（百万巨著）' },
              ]}
            />
          </Form.Item>

          <Divider />

          <div style={{ color: '#999', fontSize: 12, marginBottom: 12 }}>
            点击「创建」后将弹出目录选择对话框，请选择项目的保存位置。
            项目将自动创建完整的目录结构。
          </div>

          <Button
            type="primary"
            icon={<PlusOutlined />}
            block
            loading={creating}
            onClick={handleCreateProject}
          >
            选择目录并创建项目
          </Button>
        </Form>
      ) : (
        <div>
          {recentProjects.length === 0 ? (
            <Empty
              description="暂无最近项目"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            >
              <Button type="primary" onClick={() => setMode('create')}>
                创建新项目
              </Button>
            </Empty>
          ) : (
            <List
              grid={{ gutter: 12, xs: 1, sm: 2 }}
              dataSource={recentProjects}
              renderItem={(project) => (
                <List.Item>
                  <Card
                    size="small"
                    hoverable
                    actions={[
                      <Button
                        key="open"
                        type="link"
                        icon={<FolderOpenOutlined />}
                        onClick={() => handleOpenRecentProject(project)}
                      >
                        打开
                      </Button>,
                      <Button
                        key="remove"
                        type="link"
                        danger
                        icon={<DeleteOutlined />}
                        onClick={() => handleRemoveRecentProject(project)}
                      >
                        移除
                      </Button>,
                    ]}
                  >
                    <Card.Meta
                      avatar={<ProjectOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                      title={project.name}
                      description={
                        <div style={{ fontSize: 12, color: '#999' }}>
                          <div style={{ marginBottom: 4 }}>
                            <Tag>{GENRE_OPTIONS.find(g => g.value === project.genre)?.label || project.genre}</Tag>
                            <Tag color={project.status === 'writing' ? 'green' : 'orange'}>
                              {project.status === 'writing' ? '创作中' : '规划中'}
                            </Tag>
                          </div>
                          <div style={{ wordBreak: 'break-all', fontSize: 11 }}>
                            {project.path}
                          </div>
                        </div>
                      }
                    />
                  </Card>
                </List.Item>
              )}
            />
          )}
        </div>
      )}
    </Modal>
  )
}

export default ProjectManager

/**
 * 导出管理器
 * 支持 Markdown 和 EPUB 格式导出
 */

import path from 'path'

import { useState } from 'react'
import {
  Button,
  Space,
  Modal,
  Form,
  Select,
  Switch,
  message,
  Progress,
  Alert,
  Radio,
  Divider,
  List,
  Card,
  Tag,
  Input,
} from 'antd'
import {
  DownloadOutlined,
  FileMarkdownOutlined,
  BookOutlined,
  CheckCircleOutlined,
  FolderOpenOutlined,
} from '@ant-design/icons'

interface ExportManagerProps {
  projectRoot: string | null
  projectName?: string
  visible: boolean
  onClose: () => void
}

interface ChapterInfo {
  path: string
  name: string
  volume: string
  order: number
  content?: string
}

interface ExportProgress {
  current: number
  total: number
  status: 'idle' | 'exporting' | 'done' | 'error'
  message: string
}

const ExportManager: React.FC<ExportManagerProps> = ({
  projectRoot,
  projectName = '小说',
  visible,
  onClose,
}) => {
  const [exportFormat, setExportFormat] = useState<'markdown' | 'epub'>('markdown')
  const [exportMode, setExportMode] = useState<'single' | 'byVolume'>('single')
  const [includeToc, setIncludeToc] = useState(true)
  const [progress, setProgress] = useState<ExportProgress>({
    current: 0,
    total: 0,
    status: 'idle',
    message: '',
  })
  const [exportPath, setExportPath] = useState<string | null>(null)

  // 加载所有章节
  const loadChapters = async (): Promise<ChapterInfo[]> => {
    if (!projectRoot) return []

    const chapters: ChapterInfo[] = []

    const readDir = async (dirPath: string, volumeName: string = '正文') => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath, entry.name)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              // 提取章节序号
              const orderMatch = entry.name.match(/第(\d+)章/)
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                volume: volumeName,
                order: orderMatch ? parseInt(orderMatch[1]) : 0,
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const existsResult = await window.electronAPI.exists(plotsDir)
    if (existsResult?.success && existsResult?.exists) {
      await readDir(plotsDir)
    }

    return chapters.sort((a, b) => {
      if (a.volume !== b.volume) return a.volume.localeCompare(b.volume)
      return a.order - b.order
    })
  }

  // 导出 Markdown
  const exportMarkdown = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml 获取标题
      let title = projectName
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
        }
      } catch {}

      setProgress({ current: 0, total: chapters.length, status: 'exporting', message: '正在导出...' })

      if (exportMode === 'single') {
        // 单文件导出
        let toc = ''
        if (includeToc) {
          toc = `# ${title}\n\n`
          toc += `> 导出时间：${new Date().toLocaleString()}\n\n`
          toc += `## 目录\n\n`
          const volumes = [...new Set(chapters.map(c => c.volume))]
          for (const vol of volumes) {
            toc += `### ${vol}\n\n`
            const volChapters = chapters.filter(c => c.volume === vol)
            for (const ch of volChapters) {
              toc += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            toc += '\n'
          }
          toc += '---\n\n'
        }

        let fullContent = toc

        // 按卷分组
        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (const vol of volumes) {
          fullContent += `\n\n# ${vol}\n\n`
          const volChapters = chapters.filter(c => c.volume === vol)

          for (let i = 0; i < volChapters.length; i++) {
            const ch = volChapters[i]
            setProgress({
              current: i + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${ch.name}`,
            })

            fullContent += `\n\n## ${ch.name}\n\n`
            fullContent += ch.content || ''
          }
        }

        // 选择导出位置
        const dirResult = await window.electronAPI.openDirectory()
        if (!dirResult.success || !dirResult.data) { message.info('已取消导出'); setProgress({ current: 0, total: 0, status: 'idle', message: '' }); return }

        const exportFile = path.join(dirResult.data!, `${title}.md`)
        try {
          const writeResult = await window.electronAPI.writeFile(exportFile, fullContent)
          if (!writeResult.success) throw new Error(writeResult.error || '写入失败')
          setExportPath(exportFile)
          setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
          message.success(`已导出到: ${exportFile}`)
        } catch (err) {
          message.error(`导出失败: ${(err as Error).message}`)
          setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
        }
      } else {
        // 按卷拆分导出
        const dirResult = await window.electronAPI.openDirectory()
        if (!dirResult.success || !dirResult.data) { message.info('已取消导出'); setProgress({ current: 0, total: 0, status: 'idle', message: '' }); return }

        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (let vi = 0; vi < volumes.length; vi++) {
          const vol = volumes[vi]
          const volChapters = chapters.filter(c => c.volume === vol)

          let volContent = `# ${vol}\n\n`
          if (includeToc) {
            volContent += `## 目录\n\n`
            for (const ch of volChapters) {
              volContent += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            volContent += '\n---\n\n'
          }

          for (let ci = 0; ci < volChapters.length; ci++) {
            const ch = volChapters[ci]
            setProgress({
              current: vi * volChapters.length + ci + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${vol}/${ch.name}`,
            })

            volContent += `\n\n## ${ch.name}\n\n`
            volContent += ch.content || ''
          }

          const exportFile = `${dirResult.data!}/${vol}.md`
          const volWriteResult = await window.electronAPI.writeFile(exportFile, volContent)
          if (!volWriteResult.success) {
            message.error(`写入失败: ${volWriteResult.error}`)
            setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
            return
          }
        }

        setExportPath(dirResult.data!)
        setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
        message.success(`已导出 ${volumes.length} 个文件到: ${dirResult.data}`)
      }
    } catch (error) {
      message.error('导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 简单 HTML 转义
  const escapeHtml = (str: string): string => {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;')
  }

  // 转换为 EPUB XHTML
  const markdownToXhtml = (md: string, chapterTitle: string): string => {
    // 简单转换：处理标题和段落
    let html = md
      .replace(/^### (.+)$/gm, '<h3>$1</h3>')
      .replace(/^## (.+)$/gm, '<h2>$1</h2>')
      .replace(/^# (.+)$/gm, '<h1>$1</h1>')
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br/>')

    return `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head>
  <title>${escapeHtml(chapterTitle)}</title>
  <style>
    body { font-family: "SimSun", serif; font-size: 1em; line-height: 1.6; margin: 1em; }
    h1, h2, h3 { text-align: center; margin: 1em 0; }
    p { text-indent: 2em; margin: 0.5em 0; }
  </style>
</head>
<body>
  <h1>${escapeHtml(chapterTitle)}</h1>
  <p>${html}</p>
</body>
</html>`
  }

  // 生成 EPUB
  const exportEpub = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml
      let title = projectName
      let author = '未知作者'
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
          if (data.author) author = String(data.author)
        }
      } catch {}

      // 选择导出位置
      const epubDirResult = await window.electronAPI.openDirectory()
      if (!epubDirResult.success || !epubDirResult.data) { message.info('已取消导出'); setProgress({ current: 0, total: 0, status: 'idle', message: '' }); return }

      const safeTitle = title.replace(/[^\w\u4e00-\u9fa5]/g, '_')
      const epubDir = `${epubDirResult.data!}/${safeTitle}_epub`
      const metaResult = await window.electronAPI.mkdir(`${epubDir}/META-INF`)
      if (!metaResult.success) { throw new Error(metaResult.error || '创建META-INF失败') }
      const chaptersResult = await window.electronAPI.mkdir(`${epubDir}/OEBPS/chapters`)
      if (!chaptersResult.success) { throw new Error(chaptersResult.error || '创建OEBPS/chapters失败') }

      // mimetype（不压缩）
      const mtResult = await window.electronAPI.writeFile(`${epubDir}/mimetype`, 'application/epub+zip')
      if (!mtResult.success) throw new Error(`写入mimetype失败: ${mtResult.error}`)

      // container.xml
      const container = `<?xml version="1.0" encoding="UTF-8"?>
<container version="1.0" xmlns="urn:oasis:names:tc:opendocument:xmlns:container">
  <rootfiles>
    <rootfile full-path="OEBPS/content.opf" media-type="application/oebps-package+xml"/>
  </rootfiles>
</container>`
      const ctResult = await window.electronAPI.writeFile(`${epubDir}/META-INF/container.xml`, container)
      if (!ctResult.success) throw new Error(`写入container.xml失败: ${ctResult.error}`)

      // 生成 content.opf
      let spineItems = ''
      let manifestItems = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        manifestItems += `    <item id="ch${i + 1}" href="chapters/${chFileName}" media-type="application/xhtml+xml"/>\n`
        spineItems += `    <itemref idref="ch${i + 1}"/>\n`
      }

      const contentOpf = `<?xml version="1.0" encoding="UTF-8"?>
<package xmlns="http://www.idpf.org/2007/opf" unique-identifier="BookId" version="2.0">
  <metadata xmlns:dc="http://purl.org/dc/elements/1.1/">
    <dc:title>${escapeHtml(title)}</dc:title>
    <dc:creator>${escapeHtml(author)}</dc:creator>
    <dc:language>zh-CN</dc:language>
    <dc:identifier id="BookId">urn:uuid:${Date.now()}</dc:identifier>
  </metadata>
  <manifest>
    ${manifestItems}
    <item id="ncx" href="toc.ncx" media-type="application/x-dtbncx+xml"/>
    <item id="toc" href="toc.xhtml" media-type="application/xhtml+xml"/>
  </manifest>
  <spine toc="ncx">
${spineItems}
  </spine>
</package>`
      const opfResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/content.opf`, contentOpf)
      if (!opfResult.success) throw new Error(`写入content.opf失败: ${opfResult.error}`)

      // 生成 toc.ncx
      let navPoints = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        navPoints += `    <navPoint id="navpoint-${i + 1}" playOrder="${i + 1}">
      <navLabel><text>${escapeHtml(ch.name)}</text></navLabel>
      <content src="chapters/${chFileName}"/>
    </navPoint>\n`
      }

      const tocNcx = `<?xml version="1.0" encoding="UTF-8"?>
<ncx xmlns="http://www.dgipart.org/2007/ncx" version="2005-1">
  <head>
    <meta name="dtb:uid" content="urn:uuid:${Date.now()}"/>
    <meta name="dtb:depth" content="1"/>
    <meta name="dtb:totalPageCount" content="0"/>
    <meta name="dtb:maxPageNumber" content="0"/>
  </head>
  <docTitle><text>${escapeHtml(title)}</text></docTitle>
  <navMap>
${navPoints}
  </navMap>
</ncx>`
      const ncxResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.ncx`, tocNcx)
      if (!ncxResult.success) throw new Error(`写入toc.ncx失败: ${ncxResult.error}`)

      // 生成章节内容
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        setProgress({
          current: i + 1,
          total: chapters.length,
          status: 'exporting',
          message: `正在处理: ${ch.name}`,
        })

        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        const xhtmlContent = markdownToXhtml(ch.content || '', ch.name)
        const chResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/chapters/${chFileName}`, xhtmlContent)
        if (!chResult.success) throw new Error(`写入章节失败: ${chResult.error}`)
      }

      // 生成 toc.xhtml (HTML目录)
      let tocHtml = `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head><title>目录</title></head>
<body>
<h1>目录</h1>
<nav xmlns="http://www.w3.org/1999/xhtml"><ol>`
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        tocHtml += `<li><a href="chapters/${chFileName}">${escapeHtml(ch.name)}</a></li>`
      }
      tocHtml += '</ol></nav></body></html>'
      const txResult = await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.xhtml`, tocHtml)
      if (!txResult.success) throw new Error(`写入toc.xhtml失败: ${txResult.error}`)

      setExportPath(epubDir)
      setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: 'EPUB结构已生成' })
      message.success(`EPUB 文件结构已生成到: ${epubDir}\n请使用 epub 生成工具打包为 .epub 文件`)
    } catch (error) {
      message.error('EPUB 导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 执行导出
  const handleExport = async () => {
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }

    if (exportFormat === 'markdown') {
      await exportMarkdown()
    } else {
      await exportEpub()
    }
  }

  const handleOpenExport = async () => {
    if (exportPath) {
      const result = await window.electronAPI.openPath(exportPath)
      if (!result.success) {
        message.error(`打开失败: ${result.error}`)
      }
    }
  }

  return (
    <Modal
      title="📦 导出小说"
      open={visible}
      onCancel={onClose}
      width={500}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div>
        <Alert
          message="导出功能可以将您的章节内容导出为标准格式，便于在其他平台发布"
          type="info"
          showIcon
          style={{ marginBottom: 16 }}
        />

        <Form layout="vertical">
          <Form.Item label="导出格式">
            <Radio.Group
              value={exportFormat}
              onChange={(e) => setExportFormat(e.target.value)}
            >
              <Radio.Button value="markdown">
                <FileMarkdownOutlined /> Markdown
              </Radio.Button>
              <Radio.Button value="epub">
                <BookOutlined /> EPUB
              </Radio.Button>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="导出模式">
            <Radio.Group
              value={exportMode}
              onChange={(e) => setExportMode(e.target.value)}
            >
              <Radio value="single">单文件</Radio>
              <Radio value="byVolume">按卷拆分</Radio>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="目录">
            <Switch checked={includeToc} onChange={setIncludeToc} />
            <span style={{ marginLeft: 8, color: '#666', fontSize: 12 }}>
              {includeToc ? '包含目录' : '不包含目录'}
            </span>
          </Form.Item>

          <Divider />

          {progress.status === 'exporting' && (
            <div style={{ marginBottom: 16 }}>
              <Progress
                percent={progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0}
                status="active"
                format={(percent) => `${progress.current}/${progress.total}`}
              />
              <div style={{ fontSize: 12, color: '#666', textAlign: 'center' }}>
                {progress.message}
              </div>
            </div>
          )}

          {progress.status === 'done' && (
            <Alert
              message="导出完成！"
              description={exportPath}
              type="success"
              showIcon
              style={{ marginBottom: 16 }}
              action={
                <Button size="small" icon={<FolderOpenOutlined />} onClick={handleOpenExport}>
                  打开
                </Button>
              }
            />
          )}

          <Space>
            <Button
              type="primary"
              icon={<DownloadOutlined />}
              onClick={handleExport}
              loading={progress.status === 'exporting'}
              disabled={!projectRoot}
            >
              开始导出
            </Button>
            <Button onClick={onClose}>
              关闭
            </Button>
          </Space>
        </Form>
      </div>
    </Modal>
  )
}

export default ExportManager

/**
 * AI 工具面板
 * 包含：智能续写、定向扩写、逻辑校验、提取事实、AI重写、AI润色、语法检查、大纲生成、风格迁移
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  Input,
  message,
  Spin,
  Modal,
  Select,
  Divider,
  Tabs,
  Alert,
  Radio,
  Slider,
} from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined,
  SaveOutlined,
  SyncOutlined,
  BulbOutlined,
  BgColorsOutlined,
  ProfileOutlined,
  ScissorOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor, { ExtractedFact } from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  getSelectedText: () => string
  onInsertText: (text: string) => void
}

type RewriteMode = 'concise' | 'expand' | 'improve'
type RewriteScope = 'chapter' | 'paragraph'

const STYLE_OPTIONS = [
  { value: '金庸', label: '金庸（武侠古典）' },
  { value: '猫腻', label: '猫腻（文笔华丽）' },
  { value: '烽火戏诸侯', label: '烽火戏诸侯（热血燃系）' },
  { value: '乌山居', label: '乌山居（简洁流畅）' },
  { value: '辰东', label: '辰东（宏大壮阔）' },
  { value: '土豆', label: '土豆（小白文爽文）' },
  { value: '古龙', label: '古龙（简洁悬疑）' },
  { value: '鲁迅', label: '鲁迅（深刻犀利）' },
  { value: '海明威', label: '海明威（简洁有力）' },
]

const AIToolsPanel = ({ chapterContent, chapterPath, getSelectedText, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')
  const [extractedFacts, setExtractedFacts] = useState<ExtractedFact[]>([])
  const [activeTool, setActiveTool] = useState<string>('continue')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }
    setActiveTool('continue')
    setGenerating(true)
    setResult('')

    try {
      const context = chapterContent.slice(-800)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容（请直接输出续写文本，不需要加标题）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`续写失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('expand')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容。要求：${prompt}

当前章节上下文：
${chapterContent.slice(-1200)}

扩写后的内容（请直接输出扩写文本）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`扩写失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('check')
    setGenerating(true)
    setResult('')

    try {
      const checkResult = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。请使用清晰的格式输出检查结果。`
        }
      )

      if (checkResult.success && checkResult.content) {
        setResult(checkResult.content)
      } else {
        message.error(checkResult.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('extract')
    setGenerating(true)
    setResult('')

    try {
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)
      setExtractedFacts(facts)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `\n点击「保存到台账」将以上事实追加写入 facts YAML 文件。`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 保存提取的事实到 facts 台账
  const handleSaveFacts = async () => {
    if (extractedFacts.length === 0) return
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setGenerating(true)
    try {
      const chapterMatch = chapterPath?.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1
      const saved = await factExtractor.extractAndSave(chapterContent, chapterNumber)
      if (saved.length > 0) {
        message.success(`已保存 ${saved.length} 条事实到台账`)
        setResult('')
        setExtractedFacts([])
      } else {
        message.error('保存失败')
      }
    } catch (error) {
      message.error('保存失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 重写（增强版）──────────────────────────────────────────────────────
  const [rewriteMode, setRewriteMode] = useState<RewriteMode>('improve')
  const [rewriteScope, setRewriteScope] = useState<RewriteScope>('chapter')
  const [rewritePromptText, setRewritePromptText] = useState('')

  const getRewritePromptForMode = (mode: RewriteMode): string => {
    const prompts: Record<RewriteMode, string> = {
      concise: '精简内容，去除冗余表达，使文字更加凝练有力',
      expand: '适度扩展细节描写，丰富场景和情感刻画',
      improve: '改善文笔和叙事节奏，提升整体可读性',
    }
    return prompts[mode]
  }

  const handleRewrite = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rewrite')
    setGenerating(true)
    setResult('')

    try {
      const modeText = rewriteMode === 'concise' ? '精简' : rewriteMode === 'expand' ? '扩展' : '改进'
      let rewriteInstruction = getRewritePromptForMode(rewriteMode)
      if (rewritePromptText) {
        rewriteInstruction += `。额外要求：${rewritePromptText}`
      }

      if (rewriteScope === 'paragraph') {
        const selectedText = getSelectedText()
        if (!selectedText || selectedText.length < 10) {
          message.warning('请先在编辑器中选中要重写的段落（至少10个字）')
          setGenerating(false)
          return
        }
        const fullPrompt = `请重写以下小说段落，保持情节和主题不变，但使文笔更优美：

原文：
${selectedText}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出原文对照，重写文本用【】包裹）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`重写失败：${error}`); setGenerating(false); }
        )
      } else {
        const fullPrompt = `请重写以下小说章节，保持情节和主题不变，但改善文笔和叙事：

原文：
${chapterContent.slice(-2000)}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出，不要加标题或说明）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`重写失败：${error}`); setGenerating(false); }
        )
      }
    } catch (error) {
      message.error('重写失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 润色 ─────────────────────────────────────────────────────────────
  const handlePolish = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('polish')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请对以下小说内容进行文笔润色，改善表达流畅度、精简冗余、提升文字质感，但不改变原意和情节：

原文：
${chapterContent.slice(-1500)}

润色后的内容（直接输出，不要加说明）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`润色失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('润色失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 语法检查 ─────────────────────────────────────────────────────────────
  const handleGrammarCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('grammar')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请检查以下小说内容中的语法错误、病句、错别字、标点错误，用【原文 → 修改后】的格式列出所有问题并给出修改建议。如果没有错误，请明确说明：

原文：
${chapterContent.slice(-1500)}

检查结果（格式示例）：
1. 【"他快速的跑过来" → "他快速地跑过来"】错别字+病句
2. 【"小明和小华是好朋友，他们经常一起玩" → "小明和小华是好朋友，他们经常一起玩耍"】用词更准确` as string

      await aiModelService.stream(
        'logic',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`检查失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('语法检查失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 大纲生成 ─────────────────────────────────────────────────────────────
  const [outlineMode, setOutlineMode] = useState<'chapter' | 'full'>('chapter')

  const handleGenerateOutline = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('outline')
    setGenerating(true)
    setResult('')

    try {
      if (outlineMode === 'chapter') {
        const fullPrompt = `请分析以下章节内容，生成该章节的详细写作大纲，包括：
1. 本章核心事件
2. 主要情节点（按顺序列出）
3. 角色出场安排
4. 高潮和转折点
5. 伏笔铺设（如有）

章节内容：
${chapterContent}

章节大纲（格式清晰）：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`大纲生成失败：${error}`); setGenerating(false); }
        )
      } else {
        const fullPrompt = `请根据以下已知章节内容，为这本小说生成整体大纲框架（包括：
- 主线剧情概述
- 主要角色弧光
- 关键情节点（起承转合）
- 世界观核心设定
- 伏笔和悬念布局

已有章节内容：
${chapterContent.slice(0, 3000)}

整体大纲框架：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`大纲生成失败：${error}`); setGenerating(false); }
        )
      }
    } catch (error) {
      message.error('大纲生成失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 风格迁移 ─────────────────────────────────────────────────────────────
  const [selectedStyle, setSelectedStyle] = useState<string>('')
  const [styleStrength, setStyleStrength] = useState<number>(80)

  const handleStyleTransfer = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!selectedStyle) {
      message.warning('请选择目标风格')
      return
    }
    setActiveTool('style')
    setGenerating(true)
    setResult('')

    try {
      const styleInfo = STYLE_OPTIONS.find(s => s.value === selectedStyle)
      const strengthDesc = styleStrength > 80 ? '强烈' : styleStrength > 50 ? '中等' : '轻微'
      const fullPrompt = `请用"${styleInfo?.label}"的风格重写以下小说内容。保持情节不变，但采用该作家特有的叙事风格、文笔特点。风格强度：${strengthDesc}（${styleStrength}%）。

原文：
${chapterContent.slice(-1500)}

风格迁移后的内容（直接输出）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`风格迁移失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('风格迁移失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果
  const handleApply = () => {
    if (!result) return
    Modal.confirm({
      title: '插入方式',
      content: '选择如何将生成内容插入编辑器：',
      okText: '追加到末尾',
      cancelText: '取消',
      onOk: () => {
        onInsertText(result)
        message.success('已追加到编辑器')
        setResult('')
      },
    })
  }

  // 替换全文
  const handleReplace = () => {
    if (!result) return
    Modal.confirm({
      title: '确认替换',
      content: '将使用生成的内容完全替换当前章节内容？',
      okText: '确认替换',
      okButtonProps: { danger: true },
      cancelText: '取消',
      onOk: () => {
        onInsertText(`__REPLACE__${result}`)
        message.success('已替换章节内容')
        setResult('')
      },
    })
  }

  // 将结果插入到光标位置
  const handleInsertAtCursor = () => {
    if (!result) return
    onInsertText(result)
    message.success('已插入到编辑器')
    setResult('')
  }

  const isReplacingTool = ['rewrite', 'polish', 'style', 'grammar'].includes(activeTool)

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具标签页 */}
      <div style={{ padding: '10px 16px 0', borderBottom: '1px solid #e8e8e8' }}>
        <Tabs
          activeKey={activeTool}
          onChange={(key) => {
            setActiveTool(key)
            setResult('')
            setExtractedFacts([])
          }}
          size="small"
          items={[
            {
              key: 'writing',
              label: '✏️ 写作',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      type="primary"
                      block
                      icon={<EditOutlined />}
                      onClick={handleContinue}
                      loading={generating && activeTool === 'continue'}
                      disabled={!chapterContent}
                    >
                      智能续写
                    </Button>
                    <Button
                      block
                      icon={<ExpandOutlined />}
                      onClick={handleExpand}
                      loading={generating && activeTool === 'expand'}
                      disabled={!chapterContent}
                    >
                      定向扩写
                    </Button>
                    <Button
                      block
                      icon={<SyncOutlined />}
                      onClick={handleRewrite}
                      loading={generating && activeTool === 'rewrite'}
                      disabled={!chapterContent}
                    >
                      AI重写
                    </Button>
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handlePolish}
                      loading={generating && activeTool === 'polish'}
                      disabled={!chapterContent}
                    >
                      AI润色
                    </Button>
                    <Button
                      block
                      icon={<ScissorOutlined />}
                      onClick={handleGrammarCheck}
                      loading={generating && activeTool === 'grammar'}
                      disabled={!chapterContent}
                    >
                      语法检查
                    </Button>

                    <TextArea
                      placeholder="扩写/重写要求（可选）"
                      rows={2}
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                    />
                  </Space>

                  {activeTool === 'rewrite' && (
                    <div style={{ marginTop: 8 }}>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写范围：</span>
                        <Radio.Group
                          value={rewriteScope}
                          onChange={(e) => setRewriteScope(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="chapter">整章</Radio.Button>
                          <Radio.Button value="paragraph">段落</Radio.Button>
                        </Radio.Group>
                        {rewriteScope === 'paragraph' && (
                          <Alert
                            message="请先在编辑器中选中要重写的段落"
                            type="info"
                            style={{ marginTop: 4, fontSize: 10 }}
                            showIcon
                          />
                        )}
                      </div>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写模式：</span>
                        <Radio.Group
                          value={rewriteMode}
                          onChange={(e) => setRewriteMode(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="concise">精简</Radio.Button>
                          <Radio.Button value="expand">扩展</Radio.Button>
                          <Radio.Button value="improve">改进</Radio.Button>
                        </Radio.Group>
                      </div>
                      <Input
                        placeholder="重写额外要求（可选）"
                        size="small"
                        value={rewritePromptText}
                        onChange={(e) => setRewritePromptText(e.target.value)}
                        style={{ width: '100%' }}
                      />
                    </div>
                  )}

                  {activeTool === 'polish' && (
                    <Alert
                      message="润色将改善文笔表达，精简冗余，但保持原意"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}

                  {activeTool === 'grammar' && (
                    <Alert
                      message="检查语法错误、病句、错别字、标点错误"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'review',
              label: '🔍 校验',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<CheckCircleOutlined />}
                      onClick={handleCheck}
                      loading={generating && activeTool === 'check'}
                      disabled={!chapterContent}
                    >
                      逻辑校验
                    </Button>
                    <Button
                      block
                      icon={<ThunderboltOutlined />}
                      onClick={handleExtract}
                      loading={generating && activeTool === 'extract'}
                      disabled={!chapterContent}
                    >
                      提取事实
                    </Button>
                  </Space>
                </div>
              ),
            },
            {
              key: 'outline',
              label: '📋 大纲',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<ProfileOutlined />}
                      onClick={() => {
                        setOutlineMode('chapter')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成本章大纲
                    </Button>
                    <Button
                      block
                      icon={<BulbOutlined />}
                      onClick={() => {
                        setOutlineMode('full')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成整体大纲
                    </Button>
                    <Divider style={{ margin: '8px 0' }} />
                    <Select
                      placeholder="选择风格"
                      value={selectedStyle || undefined}
                      onChange={setSelectedStyle}
                      options={STYLE_OPTIONS}
                      style={{ width: '100%' }}
                      allowClear
                    />
                    {selectedStyle && (
                      <div>
                        <span style={{ fontSize: 11, color: '#666' }}>风格强度：{styleStrength}%</span>
                        <Slider
                          value={styleStrength}
                          onChange={setStyleStrength}
                          min={20}
                          max={100}
                          step={10}
                          marks={{ 20: '轻', 50: '中', 80: '强', 100: '极' }}
                        />
                      </div>
                    )}
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handleStyleTransfer}
                      loading={generating && activeTool === 'style'}
                      disabled={!chapterContent || !selectedStyle}
                    >
                      风格迁移
                    </Button>
                  </Space>
                </div>
              ),
            },
          ]}
        />
      </div>

      {/* 结果显示区 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="生成结果"
            extra={
              <Space>
                {extractedFacts.length > 0 && (
                  <Button
                    type="primary"
                    size="small"
                    icon={<SaveOutlined />}
                    onClick={handleSaveFacts}
                    loading={generating}
                  >
                    保存到台账
                  </Button>
                )}
                <Button type="link" size="small" onClick={handleInsertAtCursor}>
                  插入光标
                </Button>
                <Button type="link" size="small" onClick={handleApply}>
                  追加
                </Button>
                {isReplacingTool && (
                  <Button type="link" size="small" onClick={handleReplace} danger>
                    替换全文
                  </Button>
                )}
              </Space>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

/**
 * 角色管理页面
 * 显示角色列表、卡片展示，点击角色进入详情编辑
 */

import { useState, useEffect, useCallback } from 'react'
import {
  Card,
  Row,
  Col,
  Button,
  Input,
  Empty,
  Spin,
  Tag,
  message,
  Modal,
  Space,
  Dropdown,
} from 'antd'
import {
  PlusOutlined,
  SearchOutlined,
  UserOutlined,
  EditOutlined,
  DeleteOutlined,
  MoreOutlined,
} from '@ant-design/icons'
import type { MenuProps } from 'antd'
import CharacterDetail from './CharacterDetail'
import CharacterGraph from '../components/CharacterGraph'

interface Character {
  id: string
  name: string
  filePath: string
  mbti?: string
  appearance?: string
  ability?: string
  goal?: string
  flaw?: string
  background?: string
  notes?: string
  // 从 relationships.yaml 读取的关系
  relationships?: Array<{
    from: string
    to: string
    type: string
    strength: number
    development?: Array<{ chapter: number; event: string; strength: number }>
  }>
}

const CharactersPage: React.FC<{
  projectRoot: string | null
  onCharacterClick?: (characterName: string) => void
}> = ({ projectRoot, onCharacterClick }) => {
  const [characters, setCharacters] = useState<Character[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [selectedCharacter, setSelectedCharacter] = useState<Character | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)
  const [graphVisible, setGraphVisible] = useState(false)

  // 加载角色列表
  const loadCharacters = useCallback(async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      const charsDir = `${projectRoot}/characters`
      const dirExistsResult = await window.electronAPI.exists(charsDir)
      if (!dirExistsResult.success || !dirExistsResult.exists) {
        await window.electronAPI.mkdir(charsDir)
        setCharacters([])
        return
      }

      const entriesResult = await window.electronAPI.readdir(charsDir)
      if (!entriesResult.success) { console.error('读取characters目录失败:', entriesResult.error); setCharacters([]); return; }
      const entries = entriesResult.data || []
      const charFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      const loadedCharacters: Character[] = []
      for (const file of charFiles) {
        const filePath = `${charsDir}/${file.name}`
        const result = await window.electronAPI.yaml.read(filePath)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          const attrs = (data.key_attributes as Record<string, string>) || {}
          loadedCharacters.push({
            id: file.name.replace('.yaml', ''),
            name: String(data.name || file.name.replace('.yaml', '')),
            filePath,
            mbti: data.mbti as string | undefined,
            appearance: attrs.appearance,
            ability: attrs.ability,
            goal: attrs.goal,
            flaw: attrs.flaw,
            background: data.background as string | undefined,
            notes: data.notes as string | undefined,
          })
        }
      }

      // 加载人物关系
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      if (relResult.success && relResult.data) {
        const relData = relResult.data as Record<string, unknown>
        const rels = (relData.relationships as Character['relationships']) || []
        for (const char of loadedCharacters) {
          char.relationships = rels.filter(
            r => r.from === char.name || r.to === char.name
          )
        }
      }

      setCharacters(loadedCharacters)
    } catch (error) {
      console.error('加载角色失败:', error)
      message.error('加载角色列表失败')
    } finally {
      setLoading(false)
    }
  }, [projectRoot])

  // 新建角色
  const handleNewCharacter = () => {
    setSelectedCharacter(null)
    setDetailVisible(true)
  }

  // 编辑角色
  const handleEditCharacter = (char: Character) => {
    setSelectedCharacter(char)
    setDetailVisible(true)
  }

  // 删除角色
  const handleDeleteCharacter = async (char: Character) => {
    Modal.confirm({
      title: `确认删除角色「${char.name}」？`,
      content: '删除后可通过备份恢复，但数据将丢失。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          const result = await window.electronAPI.deleteFile(char.filePath)
          if (result.success) {
            message.success(`已删除角色「${char.name}」`)
            await loadCharacters()
          } else {
            message.error(`删除失败: ${result.error}`)
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // 保存角色后刷新
  const handleCharacterSaved = () => {
    setDetailVisible(false)
    loadCharacters()
  }

  useEffect(() => {
    loadCharacters()
  }, [projectRoot])

  // 过滤
  const filteredCharacters = characters.filter(char =>
    char.name.toLowerCase().includes(searchText.toLowerCase())
  )

  // 关系类型颜色
  const relTypeColor: Record<string, string> = {
    mentor: 'blue',
    rival: 'red',
    love: 'pink',
    family: 'green',
    friend: 'cyan',
  }

  const getRelationshipTags = (char: Character) => {
    if (!char.relationships || char.relationships.length === 0) return null
    return char.relationships.slice(0, 3).map((rel, idx) => {
      const other = rel.from === char.name ? rel.to : rel.from
      return (
        <Tag key={idx} color={relTypeColor[rel.type] || 'default'}>
          {other} ({rel.type})
        </Tag>
      )
    })
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Empty description="请先打开一个小说项目" />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具栏 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <h3 style={{ margin: 0 }}>角色列表</h3>
          <Space>
            <Button
              icon={<PlusOutlined />}
              onClick={() => setGraphVisible(true)}
              disabled={!projectRoot}
            >
              关系图
            </Button>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={handleNewCharacter}
            >
              新建角色
            </Button>
          </Space>
        </div>
        <Input
          placeholder="搜索角色..."
          prefix={<SearchOutlined />}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
      </div>

      {/* 角色卡片列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="加载中..." />
          </div>
        ) : filteredCharacters.length === 0 ? (
          <Empty
            description={searchText ? '未找到匹配的角色' : '暂无角色，点击"新建角色"开始创建'}
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <Row gutter={[16, 16]}>
            {filteredCharacters.map((char) => (
              <Col key={char.id} xs={24} sm={12} md={8} lg={6}>
                <Card
                  hoverable
                  size="small"
                  cover={
                    <div
                      style={{
                        height: 80,
                        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: '#fff',
                        fontSize: 32,
                      }}
                    >
                      <UserOutlined />
                    </div>
                  }
                  actions={[
                    <EditOutlined key="edit" onClick={(e) => { e.stopPropagation(); handleEditCharacter(char) }} />,
                    <DeleteOutlined
                      key="delete"
                      onClick={(e) => { e.stopPropagation(); handleDeleteCharacter(char) }}
                      style={{ color: '#ff4d4f' }}
                    />,
                  ]}
                  onClick={() => {
                    if (onCharacterClick) {
                      onCharacterClick(char.name)
                    }
                  }}
                >
                  <Card.Meta
                    title={
                      <div>
                        {char.name}
                        {char.mbti && (
                          <Tag color="purple" style={{ marginLeft: 8, float: 'right' }}>
                            {char.mbti}
                          </Tag>
                        )}
                      </div>
                    }
                    description={
                      <div>
                        {char.ability && (
                          <div
                            style={{
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap',
                              color: '#666',
                              fontSize: 12,
                            }}
                            title={char.ability}
                          >
                            {char.ability}
                          </div>
                        )}
                        {getRelationshipTags(char)}
                      </div>
                    }
                  />
                </Card>
              </Col>
            ))}
          </Row>
        )}
      </div>

      {/* 角色详情 Modal */}
      <CharacterDetail
        visible={detailVisible}
        character={selectedCharacter}
        projectRoot={projectRoot}
        onClose={() => setDetailVisible(false)}
        onSaved={handleCharacterSaved}
      />

      {/* 人物关系图 Modal */}
      <Modal
        title="人物关系图"
        open={graphVisible}
        onCancel={() => setGraphVisible(false)}
        width={700}
        footer={null}
        bodyStyle={{ padding: 0, height: 500, overflow: 'hidden' }}
      >
        <CharacterGraph
          projectRoot={projectRoot}
          onNodeClick={(name) => {
            const char = characters.find(c => c.name === name)
            if (char) {
              setGraphVisible(false)
              setTimeout(() => handleEditCharacter(char), 100)
            }
          }}
        />
      </Modal>
    </div>
  )
}

export default CharactersPage

/**
 * 角色详情编辑页面
 * 支持新建和编辑角色，保存为 YAML 文件
 */

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Card,
  Divider,
  message,
  Row,
  Col,
  Switch,
  Tooltip,
} from 'antd'
import {
  SaveOutlined,
  PlusOutlined,
  DeleteOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons'

const { TextArea } = Input

interface RelationshipItem {
  key: string
  target: string
  type: string
  strength: number
}

interface CharacterDetailProps {
  visible: boolean
  character: {
    id: string
    name: string
    filePath: string
    mbti?: string
    appearance?: string
    ability?: string
    goal?: string
    flaw?: string
    background?: string
    notes?: string
  } | null
  projectRoot: string | null
  onClose: () => void
  onSaved: () => void
}

const MBTI_OPTIONS = [
  'INTJ', 'INTP', 'ENTJ', 'ENTP',
  'INFJ', 'INFP', 'ENFJ', 'ENFP',
  'ISTJ', 'ISFJ', 'ESTJ', 'ESFJ',
  'ISTP', 'ISFP', 'ESTP', 'ESFP',
]

const RELATION_TYPES = [
  { value: 'mentor', label: '师徒' },
  { value: 'rival', label: '对手/敌对' },
  { value: 'love', label: '爱恋' },
  { value: 'family', label: '家族' },
  { value: 'friend', label: '朋友/盟友' },
  { value: 'master', label: '师承' },
  { value: 'enemy', label: '仇敌' },
]

const CharacterDetail: React.FC<CharacterDetailProps> = ({
  visible,
  character,
  projectRoot,
  onClose,
  onSaved,
}) => {
  const [form] = Form.useForm()
  const [saving, setSaving] = useState(false)
  const [relationships, setRelationships] = useState<RelationshipItem[]>([])

  // 填充表单
  useEffect(() => {
    if (visible && character) {
      form.setFieldsValue({
        name: character.name,
        mbti: character.mbti,
        appearance: character.appearance,
        ability: character.ability,
        goal: character.goal,
        flaw: character.flaw,
        background: character.background,
        notes: character.notes,
      })
    } else if (visible) {
      form.resetFields()
    }
  }, [visible, character, form])

  // 加载关系数据（带竞态保护：快速切换角色时取消旧请求）
  useEffect(() => {
    let cancelled = false
    if (visible && character && projectRoot) {
      loadRelationships(cancelled)
    }
    return () => { cancelled = true }
  }, [visible, character, projectRoot])

  const loadRelationships = async (cancelled: boolean) => {
    if (!projectRoot) return
    try {
      const relFile = `${projectRoot}/relationships.yaml`
      const result = await window.electronAPI.yaml.read(relFile)
      if (cancelled) return
      if (result.success && result.data) {
        const relData = result.data as { relationships?: Array<{ from: string; to: string; type: string; strength: number }> }
        const rels = (relData.relationships || []).filter(
          r => r.from === character?.name || r.to === character?.name
        )
        setRelationships(
          rels.map((r, idx) => ({
            key: `${idx}`,
            target: r.from === character?.name ? r.to : r.from,
            type: r.type,
            strength: r.strength,
          }))
        )
      }
    } catch (error) {
      console.error('加载关系失败:', error)
      message.error('加载人物关系失败，请检查关系文件')
    }
  }

  // 添加关系
  const handleAddRelationship = () => {
    setRelationships(prev => [
      ...prev,
      { key: Date.now().toString(), target: '', type: 'friend', strength: 0.5 },
    ])
  }

  // 删除关系
  const handleRemoveRelationship = (key: string) => {
    setRelationships(prev => prev.filter(r => r.key !== key))
  }

  // 保存角色
  const handleSave = async () => {
    try {
      const values = await form.validateFields()

      if (!values.name) {
        message.error('请输入角色名称')
        return
      }

      if (!projectRoot) {
        message.error('未设置项目根路径')
        return
      }

      setSaving(true)

      // 构建角色数据
      const charData: Record<string, unknown> = {
        name: values.name,
        mbti: values.mbti,
        key_attributes: {
          appearance: values.appearance,
          ability: values.ability,
          goal: values.goal,
          flaw: values.flaw,
        },
        background: values.background,
        notes: values.notes,
      }

      // 确定文件路径
      const safeName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const filePath = `${projectRoot}/characters/${safeName}.yaml`

      const result = await window.electronAPI.yaml.write(filePath, charData)
      if (!result.success) {
        message.error(`保存失败: ${result.error}`)
        setSaving(false)
        return
      }

      // 更新关系文件
      if (character?.name && character.name !== values.name) {
        // 角色改名，更新关系文件
        const relFile = `${projectRoot}/relationships.yaml`
        const relResult = await window.electronAPI.yaml.read(relFile)
        if (relResult.success && relResult.data) {
          const relData = relResult.data as {
            relationships?: Array<{
              from: string; to: string; type: string; strength: number; development?: unknown[]
            }>
          }
          const rels = relData.relationships || []
          const updatedRels = rels.map(r => {
            if (r.from === character.name) return { ...r, from: values.name }
            if (r.to === character.name) return { ...r, to: values.name }
            return r
          })
          try {
            await window.electronAPI.yaml.write(relFile, { relationships: updatedRels })
          } catch (writeErr) {
            console.error('更新关系文件失败:', writeErr)
            message.error('角色已保存，但关系更新失败')
            setSaving(false)
            return
          }
        }
      }

      // 保存关系
      if (values.name) {
        const relFile = `${projectRoot}/relationships.yaml`
        const relResult = await window.electronAPI.yaml.read(relFile)
        let relData = (relResult.success && relResult.data) as {
          relationships?: Array<{
            from: string; to: string; type: string; strength: number; development?: unknown[]
          }>
        } || { relationships: [] }

        // 移除旧关系（如果编辑的是已有角色）
        if (character?.name) {
          relData.relationships = (relData.relationships || []).filter(
            r => r.from !== character.name && r.to !== character.name
          )
        }

        // 构建关系列表
        const finalRels = relationships
          .filter(r => r.target && r.type)
          .map(r => ({
            from: character?.name || values.name,
            to: r.target,
            type: r.type,
            strength: r.strength,
            development: [{ chapter: 1, event: '初遇', strength: r.strength }],
          }))

        relData.relationships = [...(relData.relationships || []), ...finalRels]
        const relWriteResult = await window.electronAPI.yaml.write(relFile, relData)
        if (!relWriteResult.success) {
          message.error(`关系保存失败: ${relWriteResult.error}`)
          setSaving(false)
          return
        }
      }

      message.success('角色已保存')
      onSaved()
    } catch (error) {
      console.error('保存角色失败:', error)
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  return (
    <Modal
      title={character ? `编辑角色：${character.name}` : '新建角色'}
      open={visible}
      onCancel={onClose}
      width={800}
      footer={
        <Space>
          <Button onClick={onClose}>取消</Button>
          <Button
            type="primary"
            icon={<SaveOutlined />}
            loading={saving}
            onClick={handleSave}
          >
            保存
          </Button>
        </Space>
      }
    >
      <Form
        form={form}
        layout="vertical"
        style={{ maxHeight: '70vh', overflow: 'auto' }}
      >
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="name"
              label="角色名称"
              rules={[{ required: true, message: '请输入角色名称' }]}
            >
              <Input placeholder="如：林枫" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item name="mbti" label="MBTI">
              <Select
                placeholder="选择人格类型"
                options={MBTI_OPTIONS.map(m => ({ value: m, label: m }))}
                allowClear
              />
            </Form.Item>
          </Col>
        </Row>

        <Divider>
          <ThunderboltOutlined /> 核心属性
        </Divider>

        <Form.Item name="ability" label="能力/特长">
          <Input placeholder="如：剑术天才，重生后拥有前世记忆" />
        </Form.Item>

        <Form.Item name="goal" label="核心目标">
          <Input placeholder="如：推翻血魔宗，拯救修真界" />
        </Form.Item>

        <Form.Item name="flaw" label="核心缺陷/弱点">
          <Input placeholder="如：过于理性，不善表达情感" />
        </Form.Item>

        <Form.Item name="appearance" label="外貌特征">
          <TextArea
            placeholder="如：黑色长发，冷峻面容，眼神锐利"
            rows={2}
          />
        </Form.Item>

        <Divider>背景故事</Divider>

        <Form.Item name="background" label="背景">
          <TextArea
            placeholder="角色背景故事..."
            rows={4}
          />
        </Form.Item>

        <Form.Item name="notes" label="创作笔记">
          <TextArea
            placeholder="如：后期需要设计一个情感突破口..."
            rows={3}
          />
        </Form.Item>

        <Divider>人物关系</Divider>

        <div style={{ marginBottom: 12 }}>
          <Button
            type="dashed"
            icon={<PlusOutlined />}
            onClick={handleAddRelationship}
            block
          >
            添加关系
          </Button>
        </div>

        {relationships.map((rel, idx) => (
          <Card
            key={rel.key}
            size="small"
            style={{ marginBottom: 8 }}
          >
            <Row gutter={12} align="middle">
              <Col span={8}>
                <Input
                  placeholder="对方角色名"
                  value={rel.target}
                  onChange={(e) => {
                    const updated = [...relationships]
                    updated[idx].target = e.target.value
                    setRelationships(updated)
                  }}
                />
              </Col>
              <Col span={6}>
                <Select
                  value={rel.type}
                  onChange={(val) => {
                    const updated = [...relationships]
                    updated[idx].type = val
                    setRelationships(updated)
                  }}
                  options={RELATION_TYPES}
                  style={{ width: '100%' }}
                />
              </Col>
              <Col span={6}>
                <Input
                  type="number"
                  min={0}
                  max={1}
                  step={0.1}
                  placeholder="强度 0-1"
                  value={rel.strength}
                  onChange={(e) => {
                    const updated = [...relationships]
                    updated[idx].strength = parseFloat(e.target.value) || 0
                    setRelationships(updated)
                  }}
                />
              </Col>
              <Col span={4}>
                <Button
                  type="text"
                  danger
                  icon={<DeleteOutlined />}
                  onClick={() => handleRemoveRelationship(rel.key)}
                />
              </Col>
            </Row>
          </Card>
        ))}

        {relationships.length === 0 && (
          <div style={{ color: '#999', textAlign: 'center', padding: 16 }}>
            暂无关系，点击上方按钮添加
          </div>
        )}
      </Form>
    </Modal>
  )
}

export default CharacterDetail

/**
 * 世界设定页面
 * 显示世界观设定列表，支持新建、编辑、删除设定
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Row,
  Col,
  Button,
  Input,
  Empty,
  Spin,
  Tag,
  message,
  Modal,
  List,
  Space,
  Dropdown,
} from 'antd'
import {
  PlusOutlined,
  SearchOutlined,
  EditOutlined,
  DeleteOutlined,
  SettingOutlined,
  CheckCircleOutlined,
} from '@ant-design/icons'
import type { MenuProps } from 'antd'
import SettingDetail from './SettingDetail'
import aiModelService from '../services/aiModels'

interface WorldSetting {
  id: string
  name: string
  filePath: string
  summary?: string
  category?: string
}

interface SettingsPageProps {
  projectRoot: string | null
}

const SettingsPage: React.FC<SettingsPageProps> = ({ projectRoot }) => {
  const [settings, setSettings] = useState<WorldSetting[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [selectedSetting, setSelectedSetting] = useState<WorldSetting | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)
  const [checkingConsistency, setCheckingConsistency] = useState(false)

  // 加载设定列表
  const loadSettings = async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      const settingsDir = `${projectRoot}/settings`
      const dirExistsResult = await window.electronAPI.exists(settingsDir)
      if (!dirExistsResult.success || !dirExistsResult.exists) {
        await window.electronAPI.mkdir(settingsDir)
        setSettings([])
        return
      }

      const entriesResult = await window.electronAPI.readdir(settingsDir)
      if (!entriesResult.success) { console.error('读取settings目录失败:', entriesResult.error); message.error('读取目录失败，请检查目录权限'); setSettings([]); return; }
      const entries = entriesResult.data || []
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      const loadedSettings: WorldSetting[] = []
      for (const file of settingFiles) {
        const filePath = `${settingsDir}/${file.name}`
        const result = await window.electronAPI.yaml.read(filePath)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          // 提取第一行作为摘要（去掉 # 注释）
          const rawContent = typeof data._raw === 'string'
            ? data._raw
            : ''
          loadedSettings.push({
            id: file.name.replace('.yaml', ''),
            name: String(data.name || file.name.replace('.yaml', '')),
            filePath,
            summary: typeof data.summary === 'string' ? data.summary : rawContent.slice(0, 100),
            category: data.category as string | undefined,
          })
        } else {
          message.warning(`读取 ${file.name} 失败，跳过`)
        }
      }

      setSettings(loadedSettings)
    } catch (error) {
      console.error('加载设定失败:', error)
      message.error('加载设定列表失败')
    } finally {
      setLoading(false)
    }
  }

  // 新建设定
  const handleNewSetting = () => {
    setSelectedSetting(null)
    setDetailVisible(true)
  }

  // 编辑设定
  const handleEditSetting = (setting: WorldSetting) => {
    setSelectedSetting(setting)
    setDetailVisible(true)
  }

  // 删除设定
  const handleDeleteSetting = async (setting: WorldSetting) => {
    Modal.confirm({
      title: `确认删除设定「${setting.name}」？`,
      content: '删除后可通过备份恢复。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          const result = await window.electronAPI.deleteFile(setting.filePath)
          if (result.success) {
            message.success(`已删除设定「${setting.name}」`)
            loadSettings()
          } else {
            message.error(`删除失败: ${result.error}`)
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // AI 一致性检查
  const handleConsistencyCheck = async () => {
    if (!projectRoot) { setCheckingConsistency(false); return }
    setCheckingConsistency(true)
    try {
      // 收集所有设定文件内容
      const settingsDir = `${projectRoot}/settings`
      const entriesResult = await window.electronAPI.readdir(settingsDir)
      if (!entriesResult.success) { console.error('读取settings目录失败:', entriesResult.error); setCheckingConsistency(false); return; }
      const entries = entriesResult.data || []
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      let allSettingsContent = ''
      for (const file of settingFiles) {
        const result = await window.electronAPI.yaml.read(`${settingsDir}/${file.name}`)
        if (result.success && result.data) {
          allSettingsContent += `\n### ${file.name.replace('.yaml', '')} ###\n`
          allSettingsContent += JSON.stringify(result.data, null, 2)
        }
      }

      if (!allSettingsContent.trim()) {
        message.warning('暂无设定可检查')
        setCheckingConsistency(false)
        return
      }

      const checkPrompt = `请检查以下世界设定内容，找出其中的矛盾点和不一致之处：

${allSettingsContent}

检查维度：
1. 战力体系是否矛盾（等级划分是否自洽）
2. 地理/空间设定是否冲突
3. 势力/门派设定是否矛盾
4. 时间线是否自洽
5. 能力设定是否有冲突

请列出发现的所有矛盾点，并给出修改建议。如果一切自洽，也请明确说明。`

      const result = await aiModelService.call(
        'logic',
        checkPrompt,
        {
          systemPrompt: '你是一个严格的世界观设定审核专家。请仔细检查设定的逻辑一致性。',
        }
      )

      if (result.success && result.content) {
        Modal.info({
          title: '🏛️ 世界观一致性检查结果',
          content: (
            <pre style={{
              maxHeight: 400,
              overflow: 'auto',
              whiteSpace: 'pre-wrap',
              fontSize: 13,
              fontFamily: 'monospace',
            }}>
              {result.content}
            </pre>
          ),
          width: 700,
          okText: '关闭',
        })
      } else {
        message.error(result.error || '检查失败')
      }
    } catch (error) {
      message.error('一致性检查失败')
    } finally {
      setCheckingConsistency(false)
    }
  }

  // 保存后刷新
  const handleSettingSaved = async () => {
    setDetailVisible(false)
    try {
      await loadSettings()
    } catch (error) {
      message.error('刷新设定列表失败')
    }
  }

  useEffect(() => {
    loadSettings()
  }, [projectRoot])

  // 过滤
  const filteredSettings = settings.filter(s =>
    s.name.toLowerCase().includes(searchText.toLowerCase())
  )

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Empty description="请先打开一个小说项目" />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具栏 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: 10,
          }}
        >
          <h3 style={{ margin: 0 }}>世界观设定</h3>
          <Space>
            <Button
              icon={<CheckCircleOutlined />}
              onClick={handleConsistencyCheck}
              loading={checkingConsistency}
            >
              AI一致性检查
            </Button>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={handleNewSetting}
            >
              新建设定
            </Button>
          </Space>
        </div>
        <Input
          placeholder="搜索设定..."
          prefix={<SearchOutlined />}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
      </div>

      {/* 设定列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="加载中..." />
          </div>
        ) : filteredSettings.length === 0 ? (
          <Empty
            description={
              searchText
                ? '未找到匹配的设定'
                : '暂无设定，点击"新建设定"开始创建'
            }
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <List
            grid={{ gutter: 16, xs: 1, sm: 2, md: 3 }}
            dataSource={filteredSettings}
            renderItem={(item) => (
              <List.Item>
                <Card
                  hoverable
                  size="small"
                  actions={[
                    <EditOutlined
                      key="edit"
                      onClick={() => handleEditSetting(item)}
                    />,
                    <DeleteOutlined
                      key="delete"
                      onClick={() => handleDeleteSetting(item)}
                      style={{ color: '#ff4d4f' }}
                    />,
                  ]}
                >
                  <Card.Meta
                    avatar={<SettingOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                    title={
                      <div>
                        {item.name}
                        {item.category && (
                          <Tag color="blue" style={{ marginLeft: 8, float: 'right' }}>
                            {item.category}
                          </Tag>
                        )}
                      </div>
                    }
                    description={
                      item.summary && (
                        <div
                          style={{
                            fontSize: 12,
                            color: '#666',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            display: '-webkit-box',
                            WebkitLineClamp: 3,
                            WebkitBoxOrient: 'vertical',
                          }}
                        >
                          {item.summary}
                        </div>
                      )
                    }
                  />
                </Card>
              </List.Item>
            )}
          />
        )}
      </div>

      {/* 设定详情 Modal */}
      <SettingDetail
        visible={detailVisible}
        setting={selectedSetting}
        projectRoot={projectRoot}
        onClose={() => setDetailVisible(false)}
        onSaved={handleSettingSaved}
      />
    </div>
  )
}

export default SettingsPage

/**
 * 设定详情编辑页面
 * 支持新建和编辑世界观设定，保存为 YAML 文件
 */

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Divider,
  message,
} from 'antd'
import { SaveOutlined } from '@ant-design/icons'

const { TextArea } = Input

interface SettingDetailProps {
  visible: boolean
  setting: {
    id: string
    name: string
    filePath: string
    summary?: string
    category?: string
  } | null
  projectRoot: string | null
  onClose: () => void
  onSaved: () => void
}

const CATEGORIES = [
  { value: 'magic', label: '魔法/功法体系' },
  { value: 'geography', label: '地理/世界设定' },
  { value: 'faction', label: '势力/门派' },
  { value: 'timeline', label: '时间线/历史' },
  { value: 'culture', label: '文化/社会' },
  { value: 'technology', label: '科技/道具' },
  { value: 'other', label: '其他' },
]

const SettingDetail: React.FC<SettingDetailProps> = ({
  visible,
  setting,
  projectRoot,
  onClose,
  onSaved,
}) => {
  const [form] = Form.useForm()
  const [saving, setSaving] = useState(false)
  const [rawContent, setRawContent] = useState('')

  // 填充表单
  useEffect(() => {
    if (visible && setting) {
      form.setFieldsValue({
        name: setting.name,
        category: setting.category,
        summary: setting.summary,
      })
    } else if (visible) {
      form.resetFields()
    }
  }, [visible, setting, form])

  // 加载原始内容用于编辑
  useEffect(() => {
    if (visible && setting) {
      loadRawContent()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visible, setting])

  const loadRawContent = async () => {
    if (!setting) return
    try {
      const result = await window.electronAPI.readFile(setting.filePath)
      if (result.success && result.content) {
        setRawContent(result.content)
      }
    } catch (error) {
      console.error('加载设定内容失败:', error)
    }
  }

  // 保存设定
  const handleSave = async () => {
    try {
      const values = await form.validateFields()

      if (!values.name) {
        message.error('请输入设定名称')
        return
      }

      if (!projectRoot) {
        message.error('未设置项目根路径')
        return
      }

      setSaving(true)

      // 如果有原始内容（YAML格式良好），尝试解析并更新
      // 否则用表单数据构建
      // 如果用户编辑了原始内容（rawContent），优先使用 buildData 保存用户内容
      // 不再重新读取 YAML（否则用户编辑的内容会被磁盘旧版本覆盖）
      const finalData = {
        ...serializeSetting(values, !setting),
        content: rawContent || undefined,
      }

      const safeName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const filePath = `${projectRoot}/settings/${safeName}.yaml`

      const result = await window.electronAPI.yaml.write(filePath, finalData)
      if (!result.success) {
        message.error(`保存失败: ${result.error}`)
        return
      }

      message.success('设定已保存')
      onSaved()
    } catch (error) {
      console.error('保存设定失败:', error)
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  const serializeSetting = (values: Record<string, unknown>, isNew: boolean) => ({
    name: values.name,
    category: values.category,
    summary: values.summary || '',
    created_at: isNew ? new Date().toISOString().split('T')[0] : undefined,
    updated_at: new Date().toISOString().split('T')[0],
  })

  return (
    <Modal
      title={setting ? `编辑设定：${setting.name}` : '新建设定'}
      open={visible}
      onCancel={onClose}
      width={700}
      footer={
        <Space>
          <Button onClick={onClose}>取消</Button>
          <Button
            type="primary"
            icon={<SaveOutlined />}
            loading={saving}
            onClick={handleSave}
          >
            保存
          </Button>
        </Space>
      }
    >
      <Form
        form={form}
        layout="vertical"
        style={{ maxHeight: '70vh', overflow: 'auto' }}
      >
        <Form.Item
          name="name"
          label="设定名称"
          rules={[{ required: true, message: '请输入设定名称' }]}
        >
          <Input placeholder="如：魔法体系、地理设定、修真等级" />
        </Form.Item>

        <Form.Item name="category" label="分类">
          <Select
            placeholder="选择设定分类"
            options={CATEGORIES}
            allowClear
          />
        </Form.Item>

        <Form.Item name="summary" label="简介">
          <TextArea
            placeholder="简要描述此设定..."
            rows={3}
          />
        </Form.Item>

        <Divider>设定详情内容</Divider>

        <Form.Item
          extra={
            <span style={{ color: '#999', fontSize: 12 }}>
              可以直接粘贴已有的 Markdown/YAML 格式设定内容，将被正确解析
            </span>
          }
        >
          <TextArea
            placeholder="在此输入设定详细内容...
也可以直接粘贴已有的 Markdown 格式内容，例如：

## 魔法分类
### 元素魔法
- 火系: 攻击力强，消耗大
- 水系: 治疗和控制

## 魔法等级
### 学徒级
- 能使用基础元素魔法..."
            rows={15}
            value={rawContent}
            onChange={(e) => setRawContent(e.target.value)}
            style={{ fontFamily: 'monospace', fontSize: 13 }}
          />
        </Form.Item>
      </Form>
    </Modal>
  )
}

export default SettingDetail

/**
 * 应用设置页面
 * API密钥管理、模型选择、温度参数、主题切换、自动保存间隔
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Form,
  Input,
  Select,
  Slider,
  Switch,
  Button,
  Space,
  Divider,
  message,
  Alert,
  Tabs,
  Tag,
  Tooltip,
  InputNumber,
  List,
  Modal,
} from 'antd'
import {
  KeyOutlined,
  SaveOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  ApiOutlined,
  SettingOutlined,
  ExperimentOutlined,
} from '@ant-design/icons'

// 可用的 AI 服务
const AI_SERVICES = [
  { value: 'deepseek', label: 'DeepSeek', models: ['deepseek-chat', 'deepseek-reasoner'] },
  { value: 'doubao', label: '豆包 (Doubao)', models: ['doubao-pro', 'doubao-lite', 'doubao-mini'] },
]

// 主题选项
const THEME_OPTIONS = [
  { value: 'light', label: '浅色' },
  { value: 'dark', label: '深色' },
  { value: 'system', label: '跟随系统' },
]

interface AppSettings {
  // AI 设置
  aiServices: Record<string, { apiKey: string; model: string; temperature: number; enabled: boolean }>
  // 自动保存
  autoSaveInterval: number // 秒
  autoSaveEnabled: boolean
  // 外观
  theme: string
  editorFontSize: number
  editorLineHeight: number
}

const DEFAULT_SETTINGS: AppSettings = {
  aiServices: {
    deepseek: { apiKey: '', model: 'deepseek-chat', temperature: 0.7, enabled: true },
    doubao: { apiKey: '', model: 'doubao-pro', temperature: 0.8, enabled: false },
  },
  autoSaveInterval: 5,
  autoSaveEnabled: true,
  theme: 'light',
  editorFontSize: 16,
  editorLineHeight: 1.8,
}

const AppSettingsPage: React.FC = () => {
  const [form] = Form.useForm<AppSettings>()
  const [saving, setSaving] = useState(false)
  const [testingService, setTestingService] = useState<string | null>(null)
  const [testResult, setTestResult] = useState<Record<string, boolean>>({})

  // 加载设置
  const loadSettings = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('appSettings', DEFAULT_SETTINGS)
      if (result.success && result.value) {
        form.setFieldsValue(result.value as AppSettings)
      } else {
        form.setFieldsValue(DEFAULT_SETTINGS)
      }
    } catch (error) {
      form.setFieldsValue(DEFAULT_SETTINGS)
    }
  }

  useEffect(() => {
    loadSettings()
  }, [])

  // 保存设置
  const handleSave = async () => {
    try {
      const values = form.getFieldsValue()
      setSaving(true)

      // 检查是否有 API key 需要加密保存
      for (const [service, config] of Object.entries(values.aiServices || {})) {
        if (config.apiKey && !config.apiKey.startsWith('encrypted:')) {
          // 加密保存
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const encFn = window.electronAPI.safeStorage.encrypt as (text: string) => Promise<{ success: boolean; data?: Uint8Array; error?: string }>
            const encResult = await encFn(config.apiKey)
            if (encResult.success && encResult.data) {
              // 将 Uint8Array 转为 base64 字符串存储
              const base64 = btoa(String.fromCharCode(...encResult.data))
              values.aiServices[service].apiKey = `encrypted:${base64}`
            }
          } catch (e) {
            console.warn('API key 加密失败，将以明文保存（不推荐）:', e)
            message.warning('API key 加密失败，已以明文保存（请注意安全）')
          }
        }
      }

      await window.electronAPI.ai.saveSetting('appSettings', values)
      message.success('设置已保存')
    } catch (error) {
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  // 测试连接
  const handleTestConnection = async (service: string) => {
    setTestingService(service)
    setTestResult(prev => ({ ...prev, [service]: false }))
    try {
      const result = await window.electronAPI.ai.testConnection(service)
      setTestResult(prev => ({ ...prev, [service]: !!(result.success && result.result) }))
      if (result.success && result.result) {
        message.success(`${service} 连接成功`)
      } else {
        message.error(`${service} 连接失败: ${result.error || '未知错误'}`)
      }
    } catch (error) {
      setTestResult(prev => ({ ...prev, [service]: false }))
      message.error(`${service} 连接失败`)
    } finally {
      setTestingService(null)
    }
  }

  // 验证 API Key 格式（解密显示）
  const getDisplayApiKey = (apiKey: string) => {
    if (!apiKey) return ''
    if (apiKey.startsWith('encrypted:')) {
      return '••••••••（已加密）'
    }
    if (apiKey.length > 8) {
      return apiKey.slice(0, 4) + '••••••••' + apiKey.slice(-4)
    }
    return apiKey
  }

  const values = form.getFieldsValue()

  return (
    <div
      style={{
        maxWidth: 800,
        margin: '0 auto',
        padding: 24,
        overflow: 'auto',
        height: '100%',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 24,
        }}
      >
        <h2 style={{ margin: 0 }}>⚙️ 应用设置</h2>
        <Button
          type="primary"
          icon={<SaveOutlined />}
          loading={saving}
          onClick={handleSave}
        >
          保存设置
        </Button>
      </div>

      <Form
        form={form}
        layout="vertical"
        initialValues={DEFAULT_SETTINGS}
      >
        <Tabs
          items={[
            {
              key: 'ai',
              label: <span><ApiOutlined /> AI 服务</span>,
              children: (
                <div>
                  {AI_SERVICES.map(service => (
                    <Card
                      key={service.value}
                      size="small"
                      title={
                        <Space>
                          {service.label}
                          <Tag color={values.aiServices?.[service.value]?.enabled ? 'green' : 'default'}>
                            {values.aiServices?.[service.value]?.enabled ? '已启用' : '未启用'}
                          </Tag>
                        </Space>
                      }
                      style={{ marginBottom: 16 }}
                      extra={
                        <Switch
                          checked={values.aiServices?.[service.value]?.enabled}
                          onChange={(checked) => {
                            const current = form.getFieldValue(['aiServices', service.value]) || {}
                            form.setFieldsValue({
                              aiServices: {
                                [service.value]: { ...current, enabled: checked },
                              },
                            })
                          }}
                        />
                      }
                    >
                      <Form.Item
                        label="API Key"
                        name={['aiServices', service.value, 'apiKey']}
                        extra={
                          values.aiServices?.[service.value]?.apiKey && (
                            <Tag style={{ marginTop: 4 }}>
